window.LIVRO_DATA = {
    nome: "Volume 5",
    dados: [
{
    termo: "<span class='numero-ordem'>401.</span> <span class='nome-principal'>Jefté</span> <span class='subtitulo'>– o juiz rejeitado que fez um voto trágico</span>",
    definicao: "<p><strong>Jefté</strong> foi o oitavo juiz de Israel (<span class='versiculo'>Jz 11-12</span>), filho de Gileade e uma prostituta, rejeitado por seus meio-irmãos e exilado na terra de Tobe, onde liderou um grupo de aventureiros.</p><p>Durante a opressão amonita, os anciãos de Israel pediram sua ajuda. Jefté fez um voto imprudente ao Senhor: se vencesse, ofereceria em holocausto o que primeiro saísse de sua casa.</p><p>Após uma grande vitória sobre os amonitas (conquistando 20 cidades), <span class='destaque-vermelho'>sua única filha saiu ao seu encontro com tamboris</span>. Ele cumpriu o voto.</p><ul><li><strong>Debate:</strong> a tradição debate se ele a sacrificou literalmente ou a dedicou ao serviço do Senhor como virgem</li><li><strong>Guerra civil:</strong> travou uma guerra contra os efraimitas, identificando-os pela pronúncia da palavra 'Shibolete' (<span class='versiculo'>Jz 12:6</span>)</li><li><strong>Fé:</strong> foi incluído no hall da fé em <span class='versiculo'>Hb 11:32</span></li><li><strong>Nome:</strong> significa 'Deus abre'</li><li>Jefté é um exemplo de fé combinada com ignorância trágica</li><li>Sua história mostra o perigo de fazer votos precipitados</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jz 11:1-12:7; Hb 11:32</span>"
},
{
    termo: "<span class='numero-ordem'>402.</span> <span class='nome-principal'>Elifaz, o temanita</span> <span class='subtitulo'>– o principal amigo de Jó, que baseava o sofrimento na retribuição</span>",
    definicao: "<p><strong>Elifaz</strong> foi o primeiro e mais eloquente dos três amigos de Jó (<span class='versiculo'>Jó 2:11</span>; <span class='versiculo'>4-5, 15, 22</span>). Natural de Temã, uma cidade edomita famosa por sua sabedoria.</p><p>Em seus discursos, argumentava que Deus é justo e que o sofrimento é consequência direta do pecado (<span class='versiculo'>Jó 4:7-8</span>). Embora tenha se solidarizado com Jó nos primeiros sete dias de silêncio, seus conselhos eram teologicamente simplistas.</p><ul><li><strong>Nome:</strong> significa 'Deus é refinação' ou 'meu Deus é ouro fino'</li><li>Elifaz representa o erro de aplicar fórmulas teológicas universais ao sofrimento de uma pessoa inocente</li><li><strong>Consequência:</strong> Deus o repreendeu severamente no final, ordenando que oferecesse sacrifícios e que Jó intercedesse por ele (<span class='versiculo'>Jó 42:7-9</span>)</li><li>Ele confundiu conselho com acusação</li><li>Atribuiu os sofrimentos de Jó a algum pecado oculto (<span class='versiculo'>Jó 22:5-9</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jó 2:11; Jó 4-5; Jó 15; Jó 22; Jó 42:7-9</span>"
},
{
    termo: "<span class='numero-ordem'>403.</span> <span class='nome-principal'>Bildade, o suíta</span> <span class='subtitulo'>– o amigo de Jó que confiava na tradição dos antigos</span>",
    definicao: "<p><strong>Bildade</strong> foi o segundo amigo de Jó (<span class='versiculo'>Jó 2:11</span>), natural de Suá, uma região provavelmente localizada ao sul de Canaã.</p><p>Argumenta que Deus não rejeita o íntegro (<span class='versiculo'>Jó 8:20</span>) e que a prosperidade dos ímpios é passageira, insistindo que os filhos de Jó morreram por seus pecados (<span class='versiculo'>Jó 8:4</span>).</p><ul><li><strong>Nome:</strong> significa 'filho do conflito' ou 'senhor confuso'</li><li>Bildade simplifica o sofrimento e não consegue compreender a profundidade do drama de Jó</li><li><strong>Consequência:</strong> foi condenado por Deus (<span class='versiculo'>Jó 42:7-9</span>)</li><li>Ele apega-se à tradição dos pais, afirmando que 'somos do ontem e nada sabemos' (<span class='versiculo'>Jó 8:9</span>)</li><li>Bildade representa o erro de confiar cegamente na tradição humana como explicação para o sofrimento do justo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jó 2:11; Jó 8; Jó 18; Jó 25; Jó 42:7-9</span>"
},
{
    termo: "<span class='numero-ordem'>404.</span> <span class='nome-principal'>Zofar, o naamatita</span> <span class='subtitulo'>– o amigo mais rígido e dogmático de Jó</span>",
    definicao: "<p><strong>Zofar</strong> foi o terceiro amigo de Jó (<span class='versiculo'>Jó 2:11</span>), natural de Naamá, uma localidade incerta.</p><p>É o mais severo e dogmático dos três. Em seus discursos (<span class='versiculo'>Jó 11</span>; <span class='versiculo'>20</span>), acusa Jó de tagarelar e de ser justo demais aos seus próprios olhos.</p><ul><li><strong>Nome:</strong> significa 'gorjeio de pássaro' ou 'insolente'</li><li>Zofar argumenta que Deus está exigindo de Jó menos do que ele merece (<span class='versiculo'>Jó 11:6</span>)</li><li>Ele acredita que a felicidade dos ímpios é breve e que Deus retribui com rigor</li><li>Não oferece consolo, apenas julgamento</li><li><strong>Consequência:</strong> condenado junto com os outros dois amigos (<span class='versiculo'>Jó 42:7-9</span>)</li><li>Representa o erro de dogmatizar o sofrimento sem compaixão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jó 2:11; Jó 11; Jó 20; Jó 42:7-9</span>"
},
{
    termo: "<span class='numero-ordem'>405.</span> <span class='nome-principal'>Eliú, o buzita</span> <span class='subtitulo'>– o jovem mediador que antecipou o discurso de Deus</span>",
    definicao: "<p><strong>Eliú</strong> era filho de Baraquel, de Buz, e é apresentado no livro de Jó (caps. 32-37) como um jovem que ouviu todo o debate entre Jó e seus três amigos.</p><p>Ficou irado porque não conseguiram responder a Jó adequadamente. Eliú argumenta que o sofrimento pode ser disciplinar e redentor ('Deus disciplina para salvar'), e que Deus é grande e incompreensível.</p><ul><li><strong>Nome:</strong> significa 'Ele é o meu Deus'</li><li>Eliú prepara o terreno para a resposta divina</li><li><strong>Observação:</strong> embora não seja mencionado no epílogo (<span class='versiculo'>Jó 42</span>), Eliú não é repreendido por Deus</li><li>Muitos teólogos veem sua teologia como um prelúdio correto para o discurso divino</li><li>É um tipo do intercessor e do sábio que aponta para a soberania de Deus</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jó 32-37</span>"
},
{
    termo: "<span class='numero-ordem'>406.</span> <span class='nome-principal'>A mulher do fluxo de sangue (hemorroíssa)</span> <span class='subtitulo'>– anônima, curada pela fé</span>",
    definicao: "<p>A <strong>mulher do fluxo de sangue</strong> sofria de uma hemorragia há doze anos, tendo gasto tudo o que possuía com médicos sem obter cura (<span class='versiculo'>Mt 9:20-22</span>; <span class='versiculo'>Mc 5:25-34</span>; <span class='versiculo'>Lc 8:43-48</span>).</p><p>Sua condição a tornava cerimonialmente impura (<span class='versiculo'>Lv 15:25-27</span>), isolando-a social e religiosamente. Ouvindo falar de Jesus, ela acreditou que apenas tocar em suas vestes a curaria.</p><ul><li><strong>Ação:</strong> tocou na borda do manto de Jesus e foi instantaneamente curada</li><li><strong>Resposta:</strong> Jesus sentiu que poder havia saído dele e perguntou quem o havia tocado</li><li><strong>Confissão:</strong> a mulher, tremendo, confessou</li><li><strong>Elogio:</strong> <span class='destaque-amarelo'>'Filha, a tua fé te salvou; vai em paz e fica livre do teu sofrimento'</span></li><li>Ela é o exemplo máximo de fé perseverante e corajosa</li><li>Rompeu barreiras religiosas para alcançar a cura</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 9:20-22; Mc 5:25-34; Lc 8:43-48; Lv 15:25-27</span>"
},
{
    termo: "<span class='numero-ordem'>407.</span> <span class='nome-principal'>A viúva de Sarepta (mulher de Sarepta)</span> <span class='subtitulo'>– anônima, alimentada por Elias</span>",
    definicao: "<p>A <strong>viúva de Sarepta</strong> era uma viúva pobre da cidade fenícia de Sarepta (<span class='versiculo'>1Rs 17:8-24</span>), gentia e fora do pacto de Israel.</p><p>Durante a grande seca, o profeta Elias pediu a ela que lhe desse água e um pão. Ela respondeu que só tinha um punhado de farinha e um pouco de azeite.</p><p>Elias profetizou que sua farinha e azeite não se acabariam até que Deus enviasse chuva. Ela obedeceu, e o milagre sustentou sua casa por muitos dias.</p><ul><li><strong>Milagre:</strong> posteriormente, seu filho adoeceu e morreu. Elias o ressuscitou</li><li><strong>Declaração:</strong> <span class='destaque-amarelo'>'Agora sei que és homem de Deus'</span></li><li>Ela é um exemplo de fé radical em tempos de escassez</li><li><strong>NT:</strong> mencionada por Jesus em <span class='versiculo'>Lc 4:25-26</span> como exemplo de que Deus envia seus profetas aos gentios</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 17:8-24; Lc 4:25-26</span>"
},
{
    termo: "<span class='numero-ordem'>408.</span> <span class='nome-principal'>A sunamita (mulher de Suném)</span> <span class='subtitulo'>– anônima, que hospedou Eliseu e viu seu filho ressuscitado</span>",
    definicao: "<p>A <strong>sunamita</strong> era uma mulher rica da cidade de Suném (<span class='versiculo'>2Rs 4:8-37</span>), que insistiu com seu marido para construir um quarto para o profeta Eliseu em sua casa.</p><p>Em gratidão, Eliseu profetizou que ela teria um filho, embora fosse estéril e seu marido idoso. Ela duvidou, mas concebeu.</p><ul><li><strong>Tragédia:</strong> anos depois, o menino morreu de repente no campo</li><li><strong>Fé:</strong> ela não contou a ninguém, mas foi diretamente ao encontro de Eliseu</li><li><strong>Milagre:</strong> Eliseu foi à sua casa e ressuscitou o menino</li><li><strong>Restauração:</strong> mais tarde, por causa de uma fome, ela emigrou para a Filístia e, ao retornar, o rei restaurou suas terras (<span class='versiculo'>2Rs 8:1-6</span>)</li><li>Ela é um exemplo de hospitalidade generosa e de fé inabalável</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 4:8-37; 2Rs 8:1-6</span>"
},
{
    termo: "<span class='numero-ordem'>409.</span> <span class='nome-principal'>O servo do sumo sacerdote (Malco)</span> <span class='subtitulo'>– aquele que teve a orelha cortada por Pedro</span>",
    definicao: "<p><strong>Malco</strong> era o servo do sumo sacerdote Caifás (<span class='versiculo'>Jo 18:10</span>). Durante a prisão de Jesus no Getsêmani, Pedro sacou sua espada e cortou a orelha direita de Malco.</p><p>Jesus, então, tocou na orelha de Malco e o curou (<span class='versiculo'>Lc 22:51</span>), demonstrando sua misericórdia e poder mesmo no momento de sua prisão.</p><ul><li><strong>Significado:</strong> este milagre é o último realizado por Jesus antes de sua crucificação</li><li><strong>Nome:</strong> significa 'rei' (aramaico)</li><li>Malco representa a graça divina estendida até mesmo aos que vêm prender o Senhor</li><li>Sua orelha curada é um testemunho silencioso do amor e poder de Cristo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jo 18:10; Mt 26:51; Mc 14:47; Lc 22:50-51</span>"
},
{
    termo: "<span class='numero-ordem'>410.</span> <span class='nome-principal'>A mulher adúltera (perdoada por Jesus)</span> <span class='subtitulo'>– anônima, salva da pena de morte</span>",
    definicao: "<p>A <strong>mulher adúltera</strong> foi trazida a Jesus pelos escribas e fariseus, surpreendida em adultério, perguntando se deveriam apedrejá-la conforme a Lei de Moisés (<span class='versiculo'>Lv 20:10</span>; <span class='versiculo'>Dt 22:22</span>) (<span class='versiculo'>Jo 8:2-11</span>).</p><p>Jesus respondeu: <span class='destaque-amarelo'>'Aquele que dentre vós está sem pecado seja o primeiro que atire pedra contra ela'</span>. Um por um, todos foram saindo, começando pelos mais velhos.</p><ul><li><strong>Absolvição:</strong> Jesus então a absolveu: <span class='destaque-amarelo'>'Nem eu te condeno; vai e não peques mais'</span></li><li>Este episódio demonstra a graça e a misericórdia divinas superando a rigidez da lei</li><li><strong>Observação:</strong> o texto é ausente em alguns manuscritos antigos, mas amplamente aceito</li><li>Ela é o exemplo mais famoso do perdão incondicional de Cristo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jo 8:2-11 (texto de tradição duvidosa, mas amplamente aceito)</span>"
},
{
    termo: "<span class='numero-ordem'>411.</span> <span class='nome-principal'>Os dois ladrões da crucificação (Dimas e Gestas)</span> <span class='subtitulo'>– um arrependido, o outro não</span>",
    definicao: "<p>Dois criminosos foram crucificados ao lado de Jesus (<span class='versiculo'>Mt 27:38,44</span>; <span class='versiculo'>Mc 15:27,32</span>; <span class='versiculo'>Lc 23:39-43</span>). Tradicionalmente conhecidos como <strong>Dimas</strong> (o bom) e <strong>Gestas</strong> (o mau).</p><p>Inicialmente, ambos o insultavam (<span class='versiculo'>Mt 27:44</span>), mas um deles se arrependeu, repreendeu o outro e disse: <span class='destaque-amarelo'>'Jesus, lembra-te de mim quando entrares no teu reino'</span>.</p><ul><li><strong>Resposta:</strong> Jesus respondeu: <span class='destaque-amarelo'>'Em verdade te digo que hoje estarás comigo no paraíso'</span></li><li>O arrependido foi salvo no último momento, pela graça, sem obras</li><li>O outro endureceu-se até o fim</li><li>Este episódio é um dos mais encorajadores das Escrituras</li><li>Mostra que nunca é tarde para se arrepender</li><li>Dimas (nome não bíblico) tornou-se o primeiro a entrar no paraíso com Cristo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 23:39-43; Mt 27:38,44; Mc 15:27,32</span>"
},
{
    termo: "<span class='numero-ordem'>412.</span> <span class='nome-principal'>O jovem rico</span> <span class='subtitulo'>– anônimo que recusou seguir Jesus por causa das riquezas</span>",
    definicao: "<p>O <strong>jovem rico</strong> era um governante (<span class='versiculo'>Lc 18:18</span>) que correu até Jesus e perguntou: <span class='destaque-amarelo'>'Bom Mestre, que farei para herdar a vida eterna?'</span> (<span class='versiculo'>Mt 19:16-30</span>; <span class='versiculo'>Mc 10:17-31</span>; <span class='versiculo'>Lc 18:18-30</span>).</p><p>Jesus respondeu com os mandamentos, e o jovem afirmou tê-los guardado desde a sua juventude. Jesus, então, o amou e disse: <span class='destaque-amarelo'>'Vende tudo o que tens, dá aos pobres e terás um tesouro no céu; depois, vem e segue-me'</span>.</p><ul><li><strong>Reação:</strong> o jovem, que era muito rico, entristeceu-se e retirou-se</li><li><strong>Comentário:</strong> Jesus comentou sobre a dificuldade dos ricos em entrar no Reino de Deus</li><li>Ele é o exemplo trágico de quem valoriza mais os bens materiais do que o discipulado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 19:16-30; Mc 10:17-31; Lc 18:18-30</span>"
},
{
    termo: "<span class='numero-ordem'>413.</span> <span class='nome-principal'>Datã e Abirão</span> <span class='subtitulo'>– rebeldes engolidos pela terra (Números 16)</span>",
    definicao: "<p><strong>Datã e Abirão</strong> foram líderes da tribo de Rúben que se rebelaram contra Moisés e Arão, juntamente com Corá (um levita) (<span class='versiculo'>Nm 16:1-35</span>).</p><p>Acusaram Moisés de exaltar-se sobre a comunidade, questionando sua liderança. A rebelião incluía 250 líderes israelitas.</p><ul><li><strong>Proposta:</strong> Moisés propôs que cada um trouxesse incensários para que Deus escolhesse seu servo</li><li><strong>Julgamento:</strong> a terra abriu sua boca e engoliu Datã, Abirão, suas famílias e todos os seus bens</li><li>Desceram vivos ao abismo</li><li>Simultaneamente, fogo consumiu os 250 que ofereciam incenso</li><li><strong>Nomes:</strong> Datã ('pertencente ao justo'); Abirão ('meu pai é exaltado')</li><li>Este evento demonstrou o severo julgamento contra a rebeldia</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Nm 16:1-35; Nm 26:9; Dt 11:6; Sl 106:17</span>"
},
{
    termo: "<span class='numero-ordem'>414.</span> <span class='nome-principal'>Corá, filho de Isar</span> <span class='subtitulo'>– líder da rebelião contra Moisés no deserto</span>",
    definicao: "<p><strong>Corá</strong> era levita, primo de Moisés e Arão (<span class='versiculo'>Êx 6:21</span>). Liderou uma rebelião contra a liderança de Moisés e Arão, reivindicando o direito ao sacerdócio (<span class='versiculo'>Nm 16:1-35</span>).</p><p>Argumentou que 'toda a congregação é santa', desafiando a autoridade designada por Deus. Deus ordenou que cada líder trouxesse um incensário.</p><ul><li><strong>Julgamento:</strong> a terra se abriu e engoliu Datã e Abirão, enquanto Corá e seus 250 seguidores foram consumidos por fogo vindo do Senhor</li><li><strong>Descendentes:</strong> seus descendentes não foram destruídos (<span class='versiculo'>Nm 26:11</span>) e mais tarde tornaram-se os coraítas, conhecidos por seu serviço musical no templo (<span class='versiculo'>Sl 42-49, 84-85, 87-88</span>)</li><li><strong>Nome:</strong> significa 'calvície' ou 'gelo'</li><li>Corá representa a presunção de buscar honras não concedidas por Deus</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Nm 16:1-40; Nm 26:9-11; Jd 11</span>"
},
{
    termo: "<span class='numero-ordem'>415.</span> <span class='nome-principal'>A esposa de Ló</span> <span class='subtitulo'>– transformada em estátua de sal por desobediência</span>",
    definicao: "<p>A <strong>esposa de Ló</strong> acompanhou o marido na fuga da destruição de Sodoma e Gomorra (<span class='versiculo'>Gn 19:26</span>). Os anjos ordenaram que fugissem sem olhar para trás.</p><p>Enquanto a família fugia para a cidade de Zoar, ela, porém, olhou para trás e se tornou uma estátua de sal.</p><ul><li><strong>NT:</strong> Jesus a menciona como um lembrete para aqueles que buscam salvar suas vidas (<span class='versiculo'>Lc 17:32</span>)</li><li>Esta transformação é interpretada como um julgamento por sua desobediência e apego ao estilo de vida pecaminoso da cidade</li><li>Ela é um símbolo daqueles que, tendo escapado do julgamento, ainda olham para trás com saudade do mundo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 19:26; Lc 17:32; Sb 10:7</span>"
},
{
    termo: "<span class='numero-ordem'>416.</span> <span class='nome-principal'>As duas prostitutas que vieram a Salomão</span> <span class='subtitulo'>– mães disputando um bebê</span>",
    definicao: "<p>Duas prostitutas foram ao rei Salomão para resolver uma disputa sobre um bebê vivo (<span class='versiculo'>1Rs 3:16-28</span>). Ambas haviam dado à luz com poucos dias de diferença; uma delas acidentalmente matou seu filho enquanto dormia.</p><p>Para descobrir a verdadeira mãe, Salomão ordenou que a criança viva fosse dividida ao meio com uma espada.</p><ul><li><strong>Reação:</strong> a verdadeira mãe, movida por compaixão, suplicou que entregassem o bebê à outra mulher para salvar-lhe a vida</li><li>A mentirosa concordou com a divisão</li><li>Salomão então reconheceu a verdadeira mãe e lhe deu o filho</li><li>Esta história demonstrou a sabedoria divina de Salomão para todo o Israel</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 3:16-28</span>"
},
{
    termo: "<span class='numero-ordem'>417.</span> <span class='nome-principal'>O servo que devia dez mil talentos (parábola)</span> <span class='subtitulo'>– o devedor implacável</span>",
    definicao: "<p>O <strong>servo que devia dez mil talentos</strong> é o personagem central da parábola de Jesus em <span class='versiculo'>Mt 18:23-35</span>. Devia ao seu senhor a quantia astronômica de dez mil talentos (equivalente a milhões de dias de trabalho).</p><p>O senhor ordenou que ele e sua família fossem vendidos para pagar a dívida. O servo implorou por paciência, e o senhor, compadecido, perdoou totalmente a dívida.</p><ul><li><strong>Ironia:</strong> ao sair, o servo encontrou um conservo que lhe devia cem denários (valor irrisório) e, recusando-se a perdoar, mandou prendê-lo</li><li><strong>Consequência:</strong> o senhor, sabendo disso, revogou o perdão e o entregou aos torturadores</li><li>Esta parábola ilustra a incomensurável misericórdia de Deus para conosco e a obrigação de perdoarmos mutuamente</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 18:23-35</span>"
},
{
    termo: "<span class='numero-ordem'>418.</span> <span class='nome-principal'>O filho pródigo e seu irmão mais velho</span> <span class='subtitulo'>– parábola da graça e do ressentimento</span>",
    definicao: "<p>O <strong>filho pródigo</strong> e seu <strong>irmão mais velho</strong> são personagens da famosa parábola de Jesus em <span class='versiculo'>Lc 15:11-32</span>.</p><p>O filho mais novo pediu sua herança, partiu para um país distante e desperdiçou tudo em vida devassa, tornando-se um miserável pastor de porcos. Ao cair em si, retornou ao pai, que correu ao seu encontro, beijou-o e deu-lhe uma grande festa.</p><ul><li><strong>Irmão mais velho:</strong> sempre fora fiel, recusou-se a participar, ressentido com a misericórdia do pai</li><li>Este último representa a atitude dos fariseus e escribas</li><li>A parábola é o retrato mais vívido do amor incondicional de Deus</li><li>Mostra o perigo do legalismo que não celebra a graça</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 15:11-32</span>"
},
{
    termo: "<span class='numero-ordem'>419.</span> <span class='nome-principal'>O bom samaritano</span> <span class='subtitulo'>– herói anônimo da parábola de Jesus</span>",
    definicao: "<p>O <strong>bom samaritano</strong> é o personagem central da parábola de Jesus em <span class='versiculo'>Lc 10:25-37</span>. Um homem descia de Jerusalém a Jericó, foi assaltado, espancado e deixado semimorto.</p><p>Um sacerdote e um levita passaram de longe, sem ajuda. Um samaritano, grupo odiado pelos judeus, ao vê-lo, teve compaixão, cuidou de seus ferimentos, levou-o a uma hospedaria e pagou por seus cuidados.</p><ul><li><strong>Conclusão:</strong> Jesus perguntou qual dos três foi o próximo do homem assaltado. A resposta foi: 'O que usou de misericórdia'</li><li>O samaritano é o exemplo de que o amor ao próximo transcende barreiras étnicas, religiosas e sociais</li><li>É o verdadeiro cumprimento da lei</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 10:25-37</span>"
},
{
    termo: "<span class='numero-ordem'>420.</span> <span class='nome-principal'>O fariseu e o publicano (parábola)</span> <span class='subtitulo'>– o justificado e o soberbo</span>",
    definicao: "<p>O <strong>fariseu</strong> e o <strong>publicano</strong> são personagens da parábola de Jesus em <span class='versiculo'>Lc 18:9-14</span>. Dois homens subiram ao templo para orar: um fariseu e um publicano.</p><p>O fariseu orou agradecendo a Deus por não ser como os outros homens, mencionando seus jejuns e dízimos. O publicano, mantendo-se distante, nem ousava levantar os olhos ao céu, batendo no peito e clamando: <span class='destaque-amarelo'>'Deus, tem misericórdia de mim, pecador'</span>.</p><ul><li><strong>Declaração:</strong> Jesus declarou que o publicano desceu justificado</li><li><strong>Princípio:</strong> todo o que se exalta será humilhado, e o que se humilha será exaltado</li><li>Esta parábola é uma das mais claras condenações da autojustiça</li><li>É um hino à graça</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 18:9-14</span>"
},
{
    termo: "<span class='numero-ordem'>421.</span> <span class='nome-principal'>O rico e Lázaro</span> <span class='subtitulo'>– o abismo entre a riqueza egoísta e a pobreza redimida</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Lc 16:19-31</span>. Um <strong>homem rico</strong>, vestido de púrpura e linho fino, festejava esplendidamente todos os dias. À sua porta jazia um mendigo chamado <strong>Lázaro</strong>, coberto de úlceras.</p><p>Ambos morreram. Lázaro foi levado pelos anjos ao seio de Abraão. O rico foi para o Hades em tormento.</p><ul><li><strong>Pedido:</strong> o rico pediu que Abraão enviasse Lázaro para molhar sua língua</li><li><strong>Resposta:</strong> Abraão respondeu que havia um grande abismo fixo entre eles</li><li>O rico então pediu que Lázaro fosse avisar seus cinco irmãos, mas Abraão respondeu: <span class='destaque-amarelo'>'Eles têm Moisés e os Profetas; ouçam-nos'</span></li><li>Esta parábola aborda a justiça divina, o perigo do egoísmo e a suficiência das Escrituras</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 16:19-31</span>"
},
{
    termo: "<span class='numero-ordem'>422.</span> <span class='nome-principal'>O credor iníquo (parábola)</span> <span class='subtitulo'>– o juiz que não temia a Deus</span>",
    definicao: "<p>O <strong>credor iníquo</strong> é o personagem central da parábola de Jesus em <span class='versiculo'>Lc 18:1-8</span>. Um juiz que não temia a Deus nem respeitava os homens.</p><p>Uma viúva persistente vinha importuná-lo, pedindo justiça contra seu adversário. O juiz, cansado de sua insistência, atendeu-a para que ela não continuasse a molestar.</p><ul><li><strong>Conclusão:</strong> Se um juiz injusto age assim, quanto mais Deus fará justiça aos seus eleitos que clamam dia e noite?</li><li>A parábola ensina a necessidade de orar sempre e não desanimar</li><li>Contrasta a justiça humana tardia com a justiça divina pronta</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 18:1-8</span>"
},
{
    termo: "<span class='numero-ordem'>423.</span> <span class='nome-principal'>O amigo importuno (parábola)</span> <span class='subtitulo'>– o que pede pão à meia-noite</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Lc 11:5-8</span>. Um homem vai à casa de um amigo à meia-noite para pedir três pães para um viajante que chegou.</p><p>O amigo responde de dentro: 'Não me incomodes; a porta já está fechada, e meus filhos estão comigo na cama; não posso levantar-me para dar-te'.</p><ul><li><strong>Ensinamento:</strong> Jesus diz que, embora não se levante por amizade, por causa da importunação (ou perseverança), ele se levantará e dará tudo o que precisar</li><li>Esta parábola ensina sobre a persistência na oração</li><li>Garante que Deus, muito mais do que um amigo humano, atenderá aos seus que clamam</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 11:5-8</span>"
},
{
    termo: "<span class='numero-ordem'>424.</span> <span class='nome-principal'>O grão de mostarda (parábola)</span> <span class='subtitulo'>– da pequena semente à grande árvore</span>",
    definicao: "<p>Parábola de Jesus narrada em <span class='versiculo'>Mt 13:31-32</span>, <span class='versiculo'>Mc 4:30-32</span> e <span class='versiculo'>Lc 13:18-19</span>. O Reino dos Céus é comparado a um grão de mostarda, a menor de todas as sementes, mas que, quando cresce, torna-se a maior das hortaliças.</p><ul><li><strong>Símbolo:</strong> a mostarda era considerada uma erva daninha agressiva</li><li><strong>Mensagem:</strong> o crescimento exponencial do Reino de Deus a partir de um começo humilde (os doze discípulos) até abranger todas as nações</li><li>Simboliza a força e a inevitável expansão do evangelho</li><li>As aves do céu vêm aninhar-se nela</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 13:31-32; Mc 4:30-32; Lc 13:18-19</span>"
},
{
    termo: "<span class='numero-ordem'>425.</span> <span class='nome-principal'>O fermento (parábola)</span> <span class='subtitulo'>– a transformação silenciosa e interna</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Mt 13:33</span> e <span class='versiculo'>Lc 13:20-21</span>. O Reino dos Céus é comparado ao fermento que uma mulher toma e esconde em três medidas de farinha, até que toda a massa fique levedada.</p><ul><li><strong>Simbolismo:</strong> o fermento representa a influência transformadora do Reino</li><li>Age silenciosa e internamente, penetrando toda a sociedade e cultura</li><li><strong>Observação:</strong> diferente do uso do fermento como símbolo do mal em outras passagens, aqui ele simboliza a expansão inevitável e completa do evangelho</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 13:33; Lc 13:20-21</span>"
},
{
    termo: "<span class='numero-ordem'>426.</span> <span class='nome-principal'>O tesouro escondido e a pérola de grande valor (parábolas)</span> <span class='subtitulo'>– o valor inestimável do Reino</span>",
    definicao: "<p>Duas parábolas em <span class='versiculo'>Mt 13:44-46</span>.</p><p><strong>O tesouro escondido:</strong> Um homem encontra um tesouro escondido em um campo. Cheio de alegria, vende tudo o que tem e compra aquele campo.</p><p><strong>A pérola de grande valor:</strong> Um negociante busca pérolas preciosas e, ao encontrar uma de grande valor, vende tudo o que tem e a compra.</p><ul><li>Ambas ilustram o valor supremo e absoluto do Reino dos Céus</li><li>Vale a pena ser adquirido a qualquer custo</li><li>Há alegria que acompanha essa descoberta</li><li>O tesouro e a pérola representam a salvação e o relacionamento com Deus</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 13:44-46</span>"
},
{
    termo: "<span class='numero-ordem'>427.</span> <span class='nome-principal'>O semeador (parábola)</span> <span class='subtitulo'>– os diferentes corações que recebem a palavra</span>",
    definicao: "<p>Uma das parábolas mais importantes de Jesus, narrada em <span class='versiculo'>Mt 13:3-23</span>, <span class='versiculo'>Mc 4:3-20</span> e <span class='versiculo'>Lc 8:5-15</span>.</p><p>Um <strong>semeador</strong> sai a semear. Parte da semente cai à beira do caminho (as aves a comem), parte cai em terreno rochoso (nasce, mas seca por falta de raiz), parte cai entre os espinhos (é sufocada) e parte cai em boa terra (frutifica trinta, sessenta e cem por um).</p><ul><li><strong>Explicação:</strong> a semente é a palavra de Deus</li><li><strong>Terrenos:</strong> representam os diferentes corações: os que não entendem, os que recebem com alegria mas sem raiz, os que são sufocados pelas preocupações, e os que ouvem, entendem e frutificam</li><li>Esta é a parábola das parábolas</li><li>Ensina sobre a responsabilidade do ouvinte</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 13:3-23; Mc 4:3-20; Lc 8:5-15</span>"
},
{
    termo: "<span class='numero-ordem'>428.</span> <span class='nome-principal'>O joio (parábola)</span> <span class='subtitulo'>– a coexistência de bem e mal até o juízo final</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Mt 13:24-30</span>, <span class='versiculo'>36-43</span>. Um homem semeia boa semente em seu campo. Enquanto todos dormem, seu inimigo vem e semeia joio no meio do trigo.</p><p>Quando ambos crescem, os servos perguntam se devem arrancar o joio. O dono responde: <span class='destaque-amarelo'>'Não, para que, ao arrancar o joio, não arranqueis também o trigo. Deixai que ambos cresçam juntos até a colheita'</span>.</p><ul><li><strong>Explicação:</strong> o semeador é o Filho do Homem, o campo é o mundo, o trigo são os filhos do Reino, o joio são os filhos do maligno</li><li>A colheita é o fim do mundo</li><li>Esta parábola ensina que Deus permite a coexistência do bem e do mal até o juízo final</li><li>Haverá a separação definitiva</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 13:24-30,36-43</span>"
},
{
    termo: "<span class='numero-ordem'>429.</span> <span class='nome-principal'>O pastor e as ovelhas (parábola)</span> <span class='subtitulo'>– o Bom Pastor que deixa as noventa e nove</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Mt 18:12-14</span> e <span class='versiculo'>Lc 15:3-7</span>. Um pastor tem cem ovelhas. Se uma delas se perde, deixa as noventa e nove e vai em busca da que se perdeu até encontrá-la.</p><p>Ao encontrá-la, a coloca sobre os ombros, cheio de alegria, e ao chegar em casa, reúne amigos e vizinhos para celebrar.</p><ul><li><strong>Conclusão:</strong> <span class='destaque-amarelo'>'Assim, não é vontade de vosso Pai celeste que pereça um só destes pequeninos'</span></li><li>Revela o coração de Deus pelos pecadores perdidos</li><li>Grande alegria nos céus pelo arrependimento de um único pecador</li><li>É um retrato do evangelho: Deus não desiste dos que se desviam</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 18:12-14; Lc 15:3-7</span>"
},
{
    termo: "<span class='numero-ordem'>430.</span> <span class='nome-principal'>A dracma perdida (parábola)</span> <span class='subtitulo'>– a busca incessante do que está perdido</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Lc 15:8-10</span>. Uma mulher tem dez dracmas (moedas de prata). Se perde uma dracma, acende uma lâmpada, varre a casa e a procura diligentemente até encontrá-la.</p><p>Ao encontrá-la, reúne amigas e vizinhas, dizendo: <span class='destaque-amarelo'>'Alegrai-vos comigo, porque achei a dracma que eu havia perdido'</span>.</p><ul><li><strong>Conclusão:</strong> <span class='destaque-amarelo'>'Assim, há alegria diante dos anjos de Deus por um pecador que se arrepende'</span></li><li>Complementa a parábola da ovelha perdida</li><li>Mostra o valor inestimável de cada alma e o zelo de Deus</li><li>A dracma, por si mesma, não pode se encontrar; depende de alguém que a procure</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 15:8-10</span>"
},
{
    termo: "<span class='numero-ordem'>431.</span> <span class='nome-principal'>A figueira estéril (parábola)</span> <span class='subtitulo'>– a paciência de Deus antes do juízo</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Lc 13:6-9</span>. Um homem plantou uma figueira em sua vinha. Por três anos, ele veio procurar fruto nela e não o encontrou.</p><p>Disse ao vinhateiro: 'Corta-a; para que está ela ainda ocupando a terra inutilmente?'. O vinhateiro respondeu: <span class='destaque-amarelo'>'Senhor, deixa-a ainda este ano, até que eu cave em torno dela e lhe deite estrume; e, se der fruto, ficará; se não, depois a mandarás cortar'</span>.</p><ul><li>Esta parábola é um alerta sobre a paciência divina e o chamado ao arrependimento</li><li>Israel era a figueira estéril</li><li>O princípio se aplica a todo indivíduo que, apesar de receber cuidados, não produz fruto para Deus</li><li>O vinhateiro (Jesus) intercede por mais tempo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 13:6-9</span>"
},
{
    termo: "<span class='numero-ordem'>432.</span> <span class='nome-principal'>As dez virgens (parábola)</span> <span class='subtitulo'>– a necessidade de preparo para a vinda do noivo</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Mt 25:1-13</span>. Dez virgens tomam suas lâmpadas e saem ao encontro do noivo. Cinco são néscias (insensatas) e cinco são prudentes.</p><p>As néscias levam suas lâmpadas, mas não levam azeite consigo. As prudentes levam azeite em seus recipientes. O noivo demorou; todas cochilaram e dormiram.</p><ul><li><strong>Chegada:</strong> à meia-noite, ouve-se um grito: 'Eis o noivo! Saí-lhe ao encontro'</li><li>As virgens se preparam, mas as néscias não têm azeite e pedem às prudentes, que recusam</li><li>Enquanto vão comprar azeite, o noivo chega e as prudentes entram para as bodas; a porta se fecha</li><li>As néscias chegam tarde e pedem para entrar, mas o noivo responde: <span class='destaque-vermelho'>'Em verdade vos digo que não vos conheço'</span></li><li><strong>Conclusão:</strong> 'Vigiai, pois, porque não sabeis o dia nem a hora'</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 25:1-13</span>"
},
{
    termo: "<span class='numero-ordem'>433.</span> <span class='nome-principal'>Os talentos (parábola)</span> <span class='subtitulo'>– a responsabilidade de usar os dons de Deus</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Mt 25:14-30</span> (<span class='versiculo'>Lc 19:12-27</span> é semelhante). Um homem, ao viajar para um país distante, chama seus servos e lhes confia seus bens: a um, cinco talentos; a outro, dois; a outro, um.</p><p>Ao voltar, pede contas. O que recebeu cinco ganhou outros cinco; o que recebeu dois ganhou outros dois; o que recebeu um, por medo, enterrou o talento.</p><ul><li><strong>Elogio:</strong> <span class='destaque-amarelo'>'Muito bem, servo bom e fiel; foste fiel no pouco, sobre o muito te colocarei; entra no gozo do teu senhor'</span></li><li><strong>Condenação:</strong> o último perdeu o talento e foi lançado nas trevas exteriores</li><li>Esta parábola ensina que Deus nos dá dons e capacidades e espera que os usemos produtivamente para o seu Reino</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 25:14-30; Lc 19:12-27 (mina)</span>"
},
{
    termo: "<span class='numero-ordem'>434.</span> <span class='nome-principal'>O juízo final (parábola das ovelhas e bodes)</span> <span class='subtitulo'>– a separação final</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Mt 25:31-46</span>. Quando o Filho do Homem vier em sua glória, todas as nações serão reunidas diante dele, e ele as separará, como o pastor separa as ovelhas dos bodes.</p><p>As ovelhas (benditos) serão colocadas à sua direita e os bodes (malditos) à esquerda.</p><ul><li><strong>Ovelhas:</strong> 'Vinde, benditos de meu Pai... porque tive fome, e me destes de comer; tive sede, e me destes de beber'</li><li><strong>Bodes:</strong> 'Apartai-vos de mim, malditos... porque tive fome, e não me destes de comer'</li><li><strong>Conclusão:</strong> <span class='destaque-vermelho'>'Em verdade vos digo que, quando o fizestes a um destes meus pequeninos irmãos, a mim o fizestes'</span></li><li>Irão para o castigo eterno, mas os justos para a vida eterna</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 25:31-46</span>"
},
{
    termo: "<span class='numero-ordem'>435.</span> <span class='nome-principal'>O construtor prudente e o insensato (parábola)</span> <span class='subtitulo'>– fundamento na rocha</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Mt 7:24-27</span> e <span class='versiculo'>Lc 6:47-49</span>. Aquele que ouve as palavras de Jesus e as pratica é como um homem prudente que construiu sua casa sobre a rocha.</p><p>Caiu a chuva, vieram as enchentes, os ventos sopraram e bateram contra aquela casa, e ela não caiu, porque tinha seu fundamento na rocha.</p><ul><li><strong>Insensato:</strong> aquele que ouve as palavras de Jesus e não as pratica é como um homem insensato que construiu sua casa sobre a areia</li><li>A casa caiu, e sua ruína foi completa</li><li>Esta é a conclusão do Sermão do Monte</li><li>Enfatiza que a verdadeira segurança não está em ouvir, mas em obedecer</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 7:24-27; Lc 6:47-49</span>"
},
{
    termo: "<span class='numero-ordem'>436.</span> <span class='nome-principal'>O grão de trigo que morre (parábola)</span> <span class='subtitulo'>– o princípio da morte para frutificar</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Jo 12:24</span>. <span class='destaque-amarelo'>'Em verdade, em verdade vos digo: se o grão de trigo, caindo na terra, não morrer, fica ele só; mas, se morrer, dá muito fruto'</span>.</p><ul><li>Jesus falava de sua própria morte iminente</li><li>O princípio se aplica a todos os discípulos: é necessário morrer para si mesmo para produzir fruto para Deus</li><li>O grão que não morre permanece estéril; o que morre multiplica-se</li><li>Esta é uma das parábolas mais concisas e profundas sobre o custo e o resultado do discipulado</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jo 12:24</span>"
},
{
    termo: "<span class='numero-ordem'>437.</span> <span class='nome-principal'>O rico insensato (parábola)</span> <span class='subtitulo'>– aquele que estoca tesouros para si mesmo</span>",
    definicao: "<p>Parábola de Jesus em <span class='versiculo'>Lc 12:16-21</span>. As terras de um homem rico produziram abundantemente. Ele pensou consigo: 'Que farei, pois não tenho onde armazenar minha colheita?'</p><p>Decidiu derrubar seus celeiros e construir outros maiores, onde guardaria todo o seu cereal e bens. Então diria a si mesmo: 'Alma, tens muitos bens depositados para muitos anos; descansa, come, bebe e alegra-te'.</p><ul><li><strong>Resposta divina:</strong> <span class='destaque-vermelho'>'Louco! Esta noite te pedirão a tua alma; e o que tens preparado, para quem será?'</span></li><li><strong>Conclusão:</strong> 'Assim é aquele que entesoura para si mesmo e não é rico para com Deus'</li><li>Esta parábola condena o egoísmo, a ganância e a falsa segurança nas riquezas</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lc 12:16-21</span>"
},
{
    termo: "<span class='numero-ordem'>438.</span> <span class='nome-principal'>O pão que desceu do céu (João 6)</span> <span class='subtitulo'>– Jesus como o verdadeiro maná</span>",
    definicao: "<p>Não é uma parábola, mas um longo discurso de Jesus em <span class='versiculo'>Jo 6:22-59</span>, após a multiplicação dos pães.</p><p>Jesus declara: <span class='destaque-amarelo'>'Eu sou o pão da vida; aquele que vem a mim jamais terá fome; e aquele que crê em mim jamais terá sede'</span>.</p><ul><li>Ele contrasta o maná dado aos pais no deserto (que morriam) com o verdadeiro pão do céu, que dá vida eterna</li><li><span class='destaque-amarelo'>'Eu sou o pão vivo que desceu do céu; se alguém comer deste pão, viverá para sempre; e o pão que eu darei pela vida do mundo é a minha carne'</span></li><li>Este discurso foi tão duro que muitos discípulos se afastaram</li><li>É uma das mais profundas revelações de Jesus sobre sua pessoa e obra</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jo 6:22-59</span>"
},
{
    termo: "<span class='numero-ordem'>439.</span> <span class='nome-principal'>O vaso do oleiro (Jeremias 18)</span> <span class='subtitulo'>– a soberania de Deus sobre as nações</span>",
    definicao: "<p>Não é uma parábola de Jesus, mas uma ilustração de Deus a Jeremias. <span class='versiculo'>Jr 18:1-11</span>: O profeta desce à casa do oleiro, e o vê trabalhar com o barro.</p><p>O vaso que ele fazia se estraga na sua mão; então, o refaz, fazendo dele outro vaso, conforme lhe pareceu melhor.</p><ul><li><strong>Mensagem:</strong> <span class='destaque-amarelo'>'Não poderei eu fazer de vós como fez este oleiro, ó casa de Israel? Eis que, como o barro na mão do oleiro, assim sois vós na minha mão'</span></li><li>Se uma nação se desviar do mal, Deus se arrependerá do mal que planejava</li><li>Se uma nação fizer o mal, Deus se arrependerá do bem que planejava</li><li>Esta passagem ensina a soberania absoluta de Deus sobre as nações e a necessidade de arrependimento</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jr 18:1-11; Rm 9:21</span>"
},
{
    termo: "<span class='numero-ordem'>440.</span> <span class='nome-principal'>O carvão em brasa (Isaías 6)</span> <span class='subtitulo'>– a purificação do profeta</span>",
    definicao: "<p>Visão de Isaías (<span class='versiculo'>Is 6:1-7</span>). O profeta vê o Senhor assentado num alto e sublime trono. Os serafins clamam: <span class='destaque-amarelo'>'Santo, Santo, Santo é o Senhor dos Exércitos; toda a terra está cheia da sua glória'</span>.</p><p>Isaías, em sua impureza, clama: <span class='destaque-vermelho'>'Ai de mim! Estou perdido! Porque sou homem de lábios impuros e habito no meio de um povo de lábios impuros; e os meus olhos viram o Rei, o Senhor dos Exércitos!'</span></p><ul><li><strong>Purificação:</strong> um dos serafins voa até ele com uma brasa viva tirada do altar, toca-lhe os lábios e declara: <span class='destaque-amarelo'>'Eis que esta brasa tocou os teus lábios; a tua culpa foi removida, e o teu pecado, perdoado'</span></li><li>Isaías então se oferece como mensageiro de Deus</li><li>Esta visão é um dos relatos mais dramáticos de purificação e comissionamento profético</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Is 6:1-8</span>"
},
{
    termo: "<span class='numero-ordem'>441.</span> <span class='nome-principal'>A sarça ardente (Êxodo 3)</span> <span class='subtitulo'>– a manifestação de Deus a Moisés</span>",
    definicao: "<p>Moisés apascentava o rebanho de seu sogro Jetro, no deserto, quando chegou ao monte Horebe (Sinai). O anjo do Senhor lhe apareceu <span class='destaque-amarelo'>numa chama de fogo no meio de uma sarça</span>. Moisés olhou, e a sarça ardia no fogo, mas não se consumia.</p><p>Deus chamou do meio da sarça: 'Moisés, Moisés!' E ordenou que tirasse as sandálias, porque o lugar onde estava era terra santa.</p><ul><li><strong>Identificação:</strong> Deus se identificou como 'o Deus de Abraão, de Isaque e de Jacó'</li><li><strong>Comissão:</strong> o comissionou para libertar Israel do Egito</li><li>Esta teofania é uma das mais importantes do Antigo Testamento</li><li>Simboliza a presença de Deus que não consome (graça) e o chamado para a missão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Êx 3:1-4:17; At 7:30-34</span>"
},
{
    termo: "<span class='numero-ordem'>442.</span> <span class='nome-principal'>A pomba e o azeite (Gênesis 8)</span> <span class='subtitulo'>– o sinal da nova criação após o dilúvio</span>",
    definicao: "<p>Noé, na arca, após o dilúvio, enviou uma pomba para ver se as águas haviam diminuído. A pomba voltou com uma <span class='destaque-amarelo'>folha de oliveira</span> no bico (<span class='versiculo'>Gn 8:11</span>), indicando que as águas haviam baixado.</p><ul><li>A oliveira e a pomba tornaram-se símbolos de paz, nova vida e reconciliação com Deus</li><li>Na unção de reis e sacerdotes, o azeite era usado</li><li>A pomba também aparece no batismo de Jesus, representando o Espírito Santo</li><li>Esta narrativa é um dos primeiros símbolos de esperança após o juízo divino</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 8:11; Mt 3:16</span>"
},
{
    termo: "<span class='numero-ordem'>443.</span> <span class='nome-principal'>A coluna de nuvem e a coluna de fogo</span> <span class='subtitulo'>– guia de Deus para Israel no deserto</span>",
    definicao: "<p>O Senhor ia adiante de Israel, de dia numa coluna de nuvem para os guiar pelo caminho, e de noite numa coluna de fogo para os alumiar, para que caminhassem de dia e de noite (<span class='versiculo'>Êx 13:21-22</span>).</p><ul><li>Nunca a coluna de nuvem se apartava do povo de dia, nem a coluna de fogo de noite (<span class='versiculo'>Êx 40:38</span>)</li><li>A nuvem também simbolizava a presença divina sobre o tabernáculo (<span class='versiculo'>Êx 40:34-35</span>)</li><li>Esta manifestação visível de Deus é um tipo da orientação e presença do Espírito Santo na vida do crente</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Êx 13:21-22; Êx 40:34-38; Nm 9:15-23; 1Co 10:1-2</span>"
},
{
    termo: "<span class='numero-ordem'>444.</span> <span class='nome-principal'>A rocha que Moisés feriu (Números 20)</span> <span class='subtitulo'>– o pecado de Moisés em Meribá</span>",
    definicao: "<p>Em Meribá, o povo reclamou por falta de água. Deus ordenou a Moisés que falasse à rocha, e ela daria água. Moisés, porém, irado com o povo, chamou-os de rebeldes e <span class='destaque-vermelho'>feriu a rocha duas vezes</span> com sua vara.</p><p>A água jorrou abundantemente, mas Deus disse a Moisés e Arão: <span class='destaque-vermelho'>'Porquanto não crestes em mim, para me santificardes diante dos filhos de Israel, por isso não introduzireis esta congregação na terra que lhes dei'</span> (<span class='versiculo'>Nm 20:12</span>).</p><ul><li><strong>Tipologia:</strong> esta rocha é interpretada no NT como um tipo de Cristo (<span class='versiculo'>1Co 10:4</span>)</li><li>A rocha que foi ferida uma vez (Cristo crucificado) não precisa ser ferida novamente</li><li>O pecado de Moisés foi desobedecer à ordem de Deus e tomar para si a glória</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Nm 20:1-13; Êx 17:1-7 (Massá e Meribá); 1Co 10:4</span>"
},
{
    termo: "<span class='numero-ordem'>445.</span> <span class='nome-principal'>Baal</span> <span class='subtitulo'>– o principal deus cananeu da fertilidade, tempestades e agricultura</span>",
    definicao: "<p><strong>Baal</strong> era a principal divindade masculina do panteão cananeu-fenício, também adorado pelos moabitas, midianitas e filisteus. Baal significa 'senhor' ou 'dono'.</p><ul><li><strong>Atribuições:</strong> deus das tempestades, da chuva, dos raios e da fertilidade</li><li>Seu culto envolvia sacrifícios, rituais de fertilidade e prostituição cultual</li><li><strong>Confronto:</strong> Elias confrontou 450 profetas de Baal no Monte Carmelo (<span class='versiculo'>1Rs 18</span>)</li><li><strong>Variação:</strong> Baal-Zebube ('Senhor das Moscas') - corrupção pejorativa de Baal-Zebul ('Príncipe Baal')</li><li>A adoração a Baal foi um dos maiores pecados de Israel e Judá</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jz 2:13; 1Rs 16:31-32; 1Rs 18:17-40; Jr 19:5; Os 2:8</span>"
},
{
    termo: "<span class='numero-ordem'>446.</span> <span class='nome-principal'>Asterote (Astarote / Astarte)</span> <span class='subtitulo'>– a deusa cananeia da fertilidade, guerra e amor</span>",
    definicao: "<p><strong>Asterote</strong> era a deusa cananeia e fenícia, equivalente à deusa mesopotâmica Ishtar e à grega Afrodite. Representava a fertilidade, o amor sensual e a guerra.</p><ul><li><strong>Culto:</strong> envolvia ritos de fertilidade, prostituição sagrada e, em alguns casos, sacrifícios de crianças</li><li><strong>Salomão:</strong> construiu um santuário para Asterote por influência de suas esposas estrangeiras (<span class='versiculo'>1Rs 11:5</span>)</li><li><strong>Plural:</strong> 'Astarotes' refere-se a imagens ou representações da deusa</li><li><strong>Samuel:</strong> ordenou que Israel abandonasse 'Baalins e Astarotes' (<span class='versiculo'>1Sm 7:4</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jz 2:13; 1Sm 7:3-4; 1Rs 11:5,33; 2Rs 23:13</span>"
},
{
    termo: "<span class='numero-ordem'>447.</span> <span class='nome-principal'>Moloque (Moleque / Milcom)</span> <span class='subtitulo'>– o deus amonita dos sacrifícios humanos de crianças</span>",
    definicao: "<p><strong>Moloque</strong> era uma divindade abominável dos amonitas (<span class='versiculo'>1Rs 11:7</span>), também conhecida como Milcom. Seu culto envolvia o <span class='destaque-vermelho'>sacrifício de crianças pelo fogo</span> no vale de Hinom (Geena).</p><ul><li><strong>Proibição:</strong> a Lei de Moisés proibia explicitamente essa prática (<span class='versiculo'>Lv 18:21</span>; <span class='versiculo'>20:2-5</span>)</li><li><strong>Reis ímpios:</strong> Acaz e Manassés introduziram esse culto</li><li><strong>Josias:</strong> aboliu o culto (<span class='versiculo'>2Rs 23:10</span>)</li><li><strong>Etimologia:</strong> derivado de 'melek' (rei), combinado com a vogal de 'boshet' (vergonha)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Lv 18:21; Lv 20:2-5; 1Rs 11:7; 2Rs 23:10; Jr 32:35; At 7:43</span>"
},
{
    termo: "<span class='numero-ordem'>448.</span> <span class='nome-principal'>Quemos (Chemosh)</span> <span class='subtitulo'>– o deus nacional dos moabitas</span>",
    definicao: "<p><strong>Quemos</strong> era a principal divindade dos moabitas (<span class='versiculo'>Nm 21:29</span>; <span class='versiculo'>Jr 48:7,13,46</span>), equivalente ao deus cananeu Baal ou ao deus amonita Moloque.</p><ul><li><strong>Culto:</strong> envolvia sacrifícios humanos, como o episódio em que o rei moabita Mesa sacrificou seu filho primogênito (<span class='versiculo'>2Rs 3:26-27</span>)</li><li><strong>Salomão:</strong> construiu um santuário a Quemos por influência de suas esposas moabitas (<span class='versiculo'>1Rs 11:7</span>)</li><li><strong>Arqueologia:</strong> a Estela de Mesa (descoberta em 1868) menciona este deus</li><li><strong>Josias:</strong> desmantelou o santuário (<span class='versiculo'>2Rs 23:13</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Nm 21:29; 1Rs 11:7,33; 2Rs 3:26-27; 2Rs 23:13; Jr 48:7,13,46</span>"
},
{
    termo: "<span class='numero-ordem'>449.</span> <span class='nome-principal'>Dagom</span> <span class='subtitulo'>– o deus dos filisteus, meio homem e meio peixe</span>",
    definicao: "<p><strong>Dagom</strong> era a principal divindade dos filisteus (<span class='versiculo'>Jz 16:23</span>), com templos em Gaza e Asdode. É representado como uma figura metade homem, metade peixe.</p><ul><li><strong>Associação:</strong> fertilidade, grãos e prosperidade marítima</li><li><strong>Etimologia:</strong> derivado de 'dag' (peixe) ou 'dagan' (grão)</li><li><strong>Arca:</strong> os filisteus colocaram a Arca da Aliança no templo de Dagom</li><li><strong>Queda:</strong> a estátua de Dagom caiu de bruços diante da Arca e, no dia seguinte, caiu novamente com a cabeça e as mãos quebradas (<span class='versiculo'>1Sm 5:1-5</span>)</li><li>Este evento demonstrou a superioridade do Senhor sobre os deuses pagãos</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jz 16:23; 1Sm 5:1-7; 1Cr 10:10</span>"
},
{
    termo: "<span class='numero-ordem'>450.</span> <span class='nome-principal'>Tamuz (Dumuzi)</span> <span class='subtitulo'>– o deus sumério da vegetação, adorado por mulheres em Ezequiel 8</span>",
    definicao: "<p><strong>Tamuz</strong> era uma divindade mesopotâmica (suméria e acadiana) associada à vegetação e às estações do ano.</p><ul><li><strong>Culto:</strong> as mulheres de Jerusalém choravam por Tamuz, num ritual de luto pela sua morte e descida ao mundo inferior</li><li><strong>Ezequiel:</strong> vê essas mulheres chorando por Tamuz à porta do templo (<span class='versiculo'>Ez 8:14</span>)</li><li>Esta era uma das abominações que provocaram a ira de Deus contra Judá</li><li>O culto a Tamuz era uma forma de sincretismo pagão dentro do próprio templo de Jerusalém</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ez 8:14</span>"
},
{
    termo: "<span class='numero-ordem'>451.</span> <span class='nome-principal'>Nergal</span> <span class='subtitulo'>– o deus de Cutá, adorado pelos samaritanos</span>",
    definicao: "<p><strong>Nergal</strong> era uma divindade mesopotâmica associada à guerra, peste e ao submundo (Irkalla). Era o deus principal da cidade de Cutá (<span class='versiculo'>2Rs 17:30</span>).</p><ul><li><strong>Origem:</strong> quando os assírios trouxeram povos estrangeiros para Samaria após o exílio de Israel, os cutitas introduziram o culto a Nergal</li><li><strong>Etimologia:</strong> significa 'casa do grande homem' ou 'rei da batalha'</li><li><strong>Mitologia:</strong> considerado o marido de Ereshkigal, deusa do submundo</li><li>Seu culto envolvia rituais de apaziguamento e sacrifícios</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 17:30</span>"
},
{
    termo: "<span class='numero-ordem'>452.</span> <span class='nome-principal'>Nisroque (Nisroch)</span> <span class='subtitulo'>– o deus assírio em cujo templo Senaqueribe foi assassinado</span>",
    definicao: "<p><strong>Nisroque</strong> é uma divindade assíria mencionada apenas em <span class='versiculo'>2Rs 19:37</span> e <span class='versiculo'>Is 37:38</span>.</p><ul><li><strong>Evento:</strong> no templo de Nisroque, em Nínive, o rei Senaqueribe foi assassinado por seus filhos Adrameleque e Sarezer</li><li>Isso ocorreu após o fracasso do cerco a Jerusalém</li><li><strong>Etimologia:</strong> incerta; algumas teorias sugerem uma corrupção de 'Nusku' (deus do fogo) ou de 'Assur' (deus principal assírio)</li><li>Este episódio marca o cumprimento da profecia de Isaías contra a Assíria</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 19:37; Is 37:38</span>"
},
{
    termo: "<span class='numero-ordem'>453.</span> <span class='nome-principal'>Rimom (Hadad-Rimom)</span> <span class='subtitulo'>– o deus sírio da tempestade, adorado por Naamã</span>",
    definicao: "<p><strong>Rimom</strong> era uma divindade síria, também conhecida como Hadad (deus da tempestade e dos trovões). Era adorado em Damasco.</p><ul><li><strong>Naamã:</strong> o general sírio, curado da lepra por Eliseu, pediu permissão ao profeta para continuar se curvando diante do deus Rimom quando acompanhasse seu rei ao templo (<span class='versiculo'>2Rs 5:18</span>)</li><li><strong>Resposta:</strong> Eliseu respondeu: 'Vai em paz'</li><li>A passagem mostra a graça de Deus para com aqueles que estão em contextos culturais difíceis</li><li><strong>Hadad-Rimom:</strong> aparece em <span class='versiculo'>Zc 12:11</span> como local de luto</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 5:18; Zc 12:11</span>"
},
{
    termo: "<span class='numero-ordem'>454.</span> <span class='nome-principal'>O Jardim do Éden</span> <span class='subtitulo'>– localização, rios e significado teológico</span>",
    definicao: "<p>O <strong>Jardim do Éden</strong> foi plantado por Deus ao oriente, onde Ele colocou o primeiro homem (<span class='versiculo'>Gn 2:8-14</span>). Dele saía um rio que se dividia em quatro cabeceiras: <strong>Pisom</strong>, <strong>Giom</strong>, <strong>Tigre</strong> e <strong>Eufrates</strong>.</p><ul><li><strong>Localização:</strong> debatida, mas as descrições sugerem uma região na Mesopotâmia</li><li><strong>Árvores:</strong> duas árvores especiais: a da Vida e a do Conhecimento do Bem e do Mal</li><li><strong>Expulsão:</strong> o querubim com a espada flamejante guardando o caminho para a árvore da vida (<span class='versiculo'>Gn 3:22-24</span>)</li><li>Simboliza a perda da imortalidade e da comunhão perfeita com Deus</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 2:8-14; Gn 3:22-24</span>"
},
{
    termo: "<span class='numero-ordem'>455.</span> <span class='nome-principal'>As dez pragas do Egito</span> <span class='subtitulo'>– julgamento de Deus sobre os deuses egípcios</span>",
    definicao: "<p>Dez catástrofes enviadas por Deus sobre o Egito (<span class='versiculo'>Êx 7-12</span>) para forçar o Faraó a libertar Israel.</p><ul><li><strong>1. Águas em sangue</strong> – contra o deus do Nilo, Hapi</li><li><strong>2. Rãs</strong> – contra a deusa-rã Heket</li><li><strong>3. Piolhos</strong> – contra o deus da terra, Geb</li><li><strong>4. Moscas</strong> – contra Uatchit, o deus mosca</li><li><strong>5. Peste no gado</strong> – contra os deuses-vaca (Ápis, Hator)</li><li><strong>6. Úlceras</strong> – contra os deuses da cura (Imhotep, Toth)</li><li><strong>7. Chuva de pedras com fogo</strong> – contra o deus do céu, Nut</li><li><strong>8. Gafanhotos</strong> – contra o deus da colheita, Serápis</li><li><strong>9. Trevas</strong> – contra o deus-sol, Rá</li><li><strong>10. Morte dos primogênitos</strong> – contra Faraó, considerado um deus vivo</li></ul><p>As pragas foram uma demonstração direta da supremacia do Senhor (Yahweh) sobre todo o panteão egípcio.</p>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Êx 7-12; Nm 33:4; Sl 78:43-51; Sl 105:27-36</span>"
},
{
    termo: "<span class='numero-ordem'>456.</span> <span class='nome-principal'>Jericó</span> <span class='subtitulo'>– a cidade das palmeiras, primeira conquista de Josué</span>",
    definicao: "<p><strong>Jericó</strong> é uma das cidades mais antigas do mundo, localizada no Vale do Jordão. Conhecida como a 'cidade das palmeiras' (<span class='versiculo'>Dt 34:3</span>).</p><ul><li><strong>Conquista:</strong> Deus ordenou que os israelitas marchassem ao redor da cidade por seis dias e, no sétimo, sete vezes; as muralhas caíram (<span class='versiculo'>Js 6:1-21</span>)</li><li><strong>Raabe:</strong> a prostituta foi poupada por ter escondido os espias (<span class='versiculo'>Js 2</span>; <span class='versiculo'>6:22-25</span>)</li><li><strong>Maldição:</strong> Josué pronunciou uma maldição sobre quem reconstruísse Jericó (<span class='versiculo'>Js 6:26</span>)</li><li><strong>NT:</strong> Jesus curou cegos em Jericó (<span class='versiculo'>Mc 10:46-52</span>) e hospedou-se na casa de Zaqueu (<span class='versiculo'>Lc 19:1-10</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Js 2:1-24; Js 6:1-27; 1Rs 16:34; Mc 10:46-52; Lc 19:1-10</span>"
},
{
    termo: "<span class='numero-ordem'>457.</span> <span class='nome-principal'>Babilônia</span> <span class='subtitulo'>– cidade da torre da confusão e do cativeiro judaico</span>",
    definicao: "<p><strong>Babilônia</strong> foi uma antiga cidade na Mesopotâmia, às margens do Eufrates. Fundada por Ninrode (<span class='versiculo'>Gn 10:9-10</span>).</p><ul><li><strong>Torre de Babel:</strong> os homens tentaram construir uma torre que chegasse ao céu; Deus confundiu sua língua (<span class='versiculo'>Gn 11:1-9</span>)</li><li><strong>Império:</strong> conquistou Judá e levou seus habitantes ao exílio (586 a.C.)</li><li><strong>Nabucodonosor:</strong> transformou-a numa das cidades mais magníficas</li><li><strong>NT:</strong> Babilônia é um símbolo da corrupção mundial e da oposição a Deus (<span class='versiculo'>Ap 17-18</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 10:9-10; Gn 11:1-9; 2Rs 24-25; Dn 1-5; Ap 17-18</span>"
},
{
    termo: "<span class='numero-ordem'>458.</span> <span class='nome-principal'>Jerusalém (Salém, Sião)</span> <span class='subtitulo'>– a cidade do grande Rei, centro da história da salvação</span>",
    definicao: "<p><strong>Jerusalém</strong> é a capital de Israel e Judá, chamada de 'cidade de Davi', 'Sião' e 'Salém' (<span class='versiculo'>Gn 14:18</span>; <span class='versiculo'>Sl 76:2</span>).</p><ul><li><strong>Conquista:</strong> originalmente uma cidade jebusita, foi conquistada por Davi</li><li><strong>Templo:</strong> Salomão construiu o Templo no Monte Moriá</li><li><strong>Destruição:</strong> destruída pelos babilônios (586 a.C.) e reconstruída sob Neemias</li><li><strong>Jesus:</strong> foi crucificado, ressuscitou e ascendeu ao céu em Jerusalém</li><li><strong>Pentecostes:</strong> o Espírito Santo desceu ali, nascendo a igreja</li><li><strong>Nova Jerusalém:</strong> descerá do céu (<span class='versiculo'>Ap 21</span>)</li><li>É a cidade mais mencionada na Bíblia</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 14:18; 2Sm 5:6-10; 1Rs 6-8; Sl 122; Is 2:2-4; Lc 19:41-44; Ap 21:2</span>"
},
{
    termo: "<span class='numero-ordem'>459.</span> <span class='nome-principal'>Sodoma e Gomorra</span> <span class='subtitulo'>– cidades destruídas por fogo e enxofre por sua iniquidade</span>",
    definicao: "<p><strong>Sodoma e Gomorra</strong> foram duas das cinco cidades da planície do Jordão destruídas por Deus no tempo de Abraão e Ló (<span class='versiculo'>Gn 19</span>).</p><ul><li><strong>Pecados:</strong> arrogância, excesso de comida, indiferença para com os pobres (<span class='versiculo'>Ez 16:49-50</span>) e imoralidade sexual (<span class='versiculo'>Jd 7</span>)</li><li><strong>Destruição:</strong> fogo e enxofre do céu</li><li><strong>Esposa de Ló:</strong> olhou para trás e tornou-se uma estátua de sal (<span class='versiculo'>Gn 19:26</span>)</li><li><strong>NT:</strong> citadas por Jesus e pelos profetas como advertência (<span class='versiculo'>Mt 10:15</span>; <span class='versiculo'>2Pe 2:6</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 13:10-13; Gn 18:16-33; Gn 19:1-29; Dt 29:23; Is 1:9-10; Ez 16:49-50; Mt 10:15; 2Pe 2:6; Jd 7</span>"
},
{
    termo: "<span class='numero-ordem'>460.</span> <span class='nome-principal'>Nínive</span> <span class='subtitulo'>– a grande capital da Assíria, que se arrependeu com a pregação de Jonas</span>",
    definicao: "<p><strong>Nínive</strong> foi a capital do Império Assírio, fundada por Ninrode (<span class='versiculo'>Gn 10:11-12</span>). Foi uma das maiores cidades da antiguidade.</p><ul><li><strong>Jonas:</strong> enviado para pregar contra sua maldade; o rei e todo o povo se arrependeram (<span class='versiculo'>Jn 3:5-10</span>)</li><li><strong>Destruição:</strong> cerca de 150 anos depois, voltou à maldade e foi destruída em 612 a.C.</li><li><strong>Profetas:</strong> Naum e Sofonias profetizaram contra Nínive</li><li><strong>Misericórdia:</strong> representa a misericórdia de Deus para com os gentios arrependidos</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 10:11-12; Jn 1:1-4:11; Na 1-3; Sf 2:13-15; Mt 12:41-42; Lc 11:30-32</span>"
},
{
    termo: "<span class='numero-ordem'>461.</span> <span class='nome-principal'>Bete-El (Betel)</span> <span class='subtitulo'>– 'Casa de Deus', lugar da escada de Jacó e da visão divina</span>",
    definicao: "<p><strong>Betel</strong> era uma cidade a cerca de 16 km ao norte de Jerusalém. Originalmente chamada Luz (<span class='versiculo'>Gn 28:19</span>).</p><ul><li><strong>Jacó:</strong> sonhou com uma escada que ligava a terra ao céu (<span class='versiculo'>Gn 28:10-22</span>)</li><li><strong>Abraão:</strong> construiu um altar ali (<span class='versiculo'>Gn 12:8</span>)</li><li><strong>Idolatria:</strong> Jeroboão I colocou um dos bezerros de ouro em Betel (<span class='versiculo'>1Rs 12:28-29</span>)</li><li><strong>Amós:</strong> profetizou contra os santuários de Betel (<span class='versiculo'>Am 4:4-5</span>; <span class='versiculo'>5:5-6</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 12:8; Gn 28:10-22; Gn 35:1-15; 1Rs 12:28-33; 1Rs 13:1-10; Am 5:5-6</span>"
},
{
    termo: "<span class='numero-ordem'>462.</span> <span class='nome-principal'>Gilgal</span> <span class='subtitulo'>– o primeiro acampamento de Israel após cruzar o Jordão</span>",
    definicao: "<p><strong>Gilgal</strong> foi o local na planície do Jordão, a leste de Jericó, onde Josué erigiu doze pedras em memória da travessia do Jordão (<span class='versiculo'>Js 4:19-24</span>).</p><ul><li><strong>Centro:</strong> foi o centro de operações para a conquista de Canaã</li><li><strong>Páscoa:</strong> celebraram a primeira Páscoa na Terra Prometida; o maná cessou (<span class='versiculo'>Js 5:10-12</span>)</li><li><strong>Samuel:</strong> julgava Israel em Gilgal (<span class='versiculo'>1Sm 7:16</span>)</li><li><strong>Idolatria:</strong> tornou-se lugar de idolatria (<span class='versiculo'>Os 4:15</span>; <span class='versiculo'>9:15</span>)</li><li><strong>Significado:</strong> relacionado a 'rolar' – Deus 'rolou' o opróbrio do Egito (<span class='versiculo'>Js 5:9</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Js 4:19-5:12; 1Sm 7:16; 1Sm 11:14-15; 1Sm 15:12-21; Am 4:4; Os 4:15</span>"
},
{
    termo: "<span class='numero-ordem'>463.</span> <span class='nome-principal'>Belém (Efrata)</span> <span class='subtitulo'>– a cidade do rei Davi e do nascimento de Jesus</span>",
    definicao: "<p><strong>Belém</strong> é uma pequena cidade a cerca de 8 km ao sul de Jerusalém, também chamada Efrata (<span class='versiculo'>Gn 35:19</span>; <span class='versiculo'>Mq 5:2</span>).</p><ul><li><strong>Raquel:</strong> morreu e foi sepultada ali</li><li><strong>Rute e Boaz:</strong> viveram e se casaram ali (<span class='versiculo'>Rt 1-4</span>)</li><li><strong>Davi:</strong> cidade natal de Davi; Samuel o ungiu rei (<span class='versiculo'>1Sm 16:1-13</span>)</li><li><strong>Jesus:</strong> local do nascimento de Jesus (<span class='versiculo'>Mt 2:1-6</span>; <span class='versiculo'>Lc 2:1-20</span>), cumprindo a profecia de Miqueias (<span class='versiculo'>Mq 5:2</span>)</li><li><strong>Significado:</strong> 'Casa do Pão' – Jesus, o 'Pão da Vida', nasceu ali</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 35:19; Rt 1-4; 1Sm 16:1-13; Mq 5:2; Mt 2:1-18; Lc 2:1-20</span>"
},
{
    termo: "<span class='numero-ordem'>464.</span> <span class='nome-principal'>Nazaré</span> <span class='subtitulo'>– a cidade da infância de Jesus, desprezada pelos judeus</span>",
    definicao: "<p><strong>Nazaré</strong> era uma cidade da Galileia, na região montanhosa, onde José e Maria viveram e onde Jesus cresceu (<span class='versiculo'>Mt 2:22-23</span>; <span class='versiculo'>Lc 2:39-40,51</span>).</p><ul><li><strong>Desprezo:</strong> Natanael perguntou: 'Pode vir alguma coisa boa de Nazaré?' (<span class='versiculo'>Jo 1:46</span>)</li><li><strong>Rejeição:</strong> Jesus foi rejeitado pelos nazarenos em sua própria sinagoga (<span class='versiculo'>Lc 4:16-30</span>)</li><li><strong>Título:</strong> 'Nazareno' tornou-se um título desprezivo para os seguidores de Jesus (<span class='versiculo'>At 24:5</span>)</li><li><strong>Etimologia:</strong> deriva de 'netser' (ramo ou renovo), ligado à profecia messiânica de <span class='versiculo'>Is 11:1</span></li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 2:22-23; Mt 21:11; Mc 1:9; Lc 2:39-40; Lc 4:16-30; Jo 1:46; At 24:5</span>"
},
{
    termo: "<span class='numero-ordem'>465.</span> <span class='nome-principal'>Cafarnaum</span> <span class='subtitulo'>– a cidade de Jesus na Galileia, 'sua própria cidade'</span>",
    definicao: "<p><strong>Cafarnaum</strong> era uma cidade na margem norte do Mar da Galileia. Jesus fez de Cafarnaum sua base durante seu ministério público na Galileia (<span class='versiculo'>Mt 9:1</span>).</p><ul><li><strong>Milagres:</strong> curou o servo do centurião (<span class='versiculo'>Mt 8:5-13</span>), o paralítico (<span class='versiculo'>Mc 2:1-12</span>), a sogra de Pedro (<span class='versiculo'>Mc 1:29-31</span>)</li><li><strong>Condenação:</strong> <span class='destaque-vermelho'>'E tu, Cafarnaum, serás elevada até o céu? Serás abatida até ao inferno'</span> (<span class='versiculo'>Mt 11:23</span>)</li><li><strong>Arqueologia:</strong> ruínas preservadas em Israel (Casa de Pedro, Sinagoga)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 4:13; Mt 8:5-13; Mt 9:1; Mt 11:23; Mc 1:21-34; Lc 4:31-37; Lc 7:1-10</span>"
},
{
    termo: "<span class='numero-ordem'>466.</span> <span class='nome-principal'>Sião (Monte Sião)</span> <span class='subtitulo'>– a colina de Jerusalém, símbolo da presença de Deus</span>",
    definicao: "<p><strong>Sião</strong> era originalmente a colina jebusita conquistada por Davi (<span class='versiculo'>2Sm 5:7</span>), tornando-se sinônimo de Jerusalém.</p><ul><li>Lugar onde Deus escolheu para fazer habitar o seu nome (<span class='versiculo'>Sl 132:13</span>)</li><li>Lugar do Templo, da arca da aliança, e da presença divina (Shekinah)</li><li>Os profetas frequentemente se referem a Sião como a esposa de Deus</li><li><strong>NT:</strong> a igreja é a Sião celestial (<span class='versiculo'>Hb 12:22</span>; <span class='versiculo'>1Pe 2:6</span>)</li><li>'Sião' aparece mais de 150 vezes na Bíblia</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 5:7; 1Rs 8:1; Sl 48:1-2; Sl 132:13; Is 2:3; Is 62:1; Hb 12:22; 1Pe 2:6</span>"
},
{
    termo: "<span class='numero-ordem'>467.</span> <span class='nome-principal'>Mar Morto (Mar Salgado, Mar da Arabá)</span> <span class='subtitulo'>– o lago da destruição de Sodoma</span>",
    definicao: "<p><strong>O Mar Morto</strong> é um lago de água salgada localizado na depressão mais baixa da Terra (cerca de 430 m abaixo do nível do mar).</p><ul><li><strong>Nomes:</strong> Mar Salgado (<span class='versiculo'>Gn 14:3</span>), Mar da Arabá (<span class='versiculo'>Dt 3:17</span>), Mar Oriental (<span class='versiculo'>Ez 47:18</span>)</li><li><strong>Salinidade:</strong> alta, impedindo a vida de peixes e plantas</li><li><strong>Sodoma:</strong> acredita-se que as cidades de Sodoma e Gomorra estavam na região sul</li><li><strong>Profecia:</strong> no reino milenar, o Mar Morto será curado e haverá pesca abundante (<span class='versiculo'>Ez 47:8-10</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 14:3; Dt 3:17; Ez 47:8-10; Zc 14:8</span>"
},
{
    termo: "<span class='numero-ordem'>468.</span> <span class='nome-principal'>Samaria</span> <span class='subtitulo'>– capital do reino do norte (Israel), centro da idolatria</span>",
    definicao: "<p><strong>Samaria</strong> foi uma cidade construída por Onri, rei de Israel, no monte Semer (<span class='versiculo'>1Rs 16:24</span>). Tornou-se capital do reino do norte.</p><ul><li>Centro de idolatria (bezerros de ouro, culto a Baal)</li><li>Elias e Eliseu atuaram ali</li><li>Conquistada pela Assíria em 722 a.C.; população deportada</li><li><strong>Samaritanos:</strong> originados da mistura de estrangeiros com judeus remanescentes (<span class='versiculo'>2Rs 17:24-41</span>)</li><li><strong>NT:</strong> Jesus encontrou a mulher samaritana no poço de Jacó (<span class='versiculo'>Jo 4</span>); Filipe pregou em Samaria (<span class='versiculo'>At 8</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 16:24; 2Rs 17:5-6; Jo 4:4-42; At 8:4-25</span>"
},
{
    termo: "<span class='numero-ordem'>469.</span> <span class='nome-principal'>Siquém</span> <span class='subtitulo'>– cidade de Abraão, local do enterro de José e do concílio de Josué</span>",
    definicao: "<p><strong>Siquém</strong> é uma cidade antiga entre os montes Gerizim e Ebal.</p><ul><li><strong>Abraão:</strong> construiu um altar ali (<span class='versiculo'>Gn 12:6-7</span>)</li><li><strong>Jacó:</strong> comprou um campo e enterrou os ídolos (<span class='versiculo'>Gn 33:18-20</span>)</li><li><strong>José:</strong> foi sepultado em Siquém (<span class='versiculo'>Js 24:32</span>)</li><li><strong>Josué:</strong> reuniu todas as tribos para fazer aliança (<span class='versiculo'>Js 24</span>)</li><li><strong>Abimeleque:</strong> se autoproclamou rei (<span class='versiculo'>Jz 9</span>)</li><li><strong>Jeroboão I:</strong> fez de Siquém sua primeira capital (<span class='versiculo'>1Rs 12:25</span>)</li><li><strong>NT:</strong> Jesus conversou com a mulher samaritana no poço de Jacó (<span class='versiculo'>Jo 4:5-6</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 12:6-7; Gn 33:18-20; Js 24; Jz 9; 1Rs 12:25; Jo 4:5-6</span>"
},
{
    termo: "<span class='numero-ordem'>470.</span> <span class='nome-principal'>Hebrom</span> <span class='subtitulo'>– cidade dos patriarcas, onde Davi reinou antes de Jerusalém</span>",
    definicao: "<p><strong>Hebrom</strong> é uma cidade antiga nas montanhas de Judá, cerca de 30 km ao sul de Jerusalém.</p><ul><li><strong>Abraão:</strong> comprou a caverna de Macpela como sepultura para Sara (<span class='versiculo'>Gn 23</span>)</li><li><strong>Patriarcas:</strong> enterrados Abraão, Isaque, Jacó, Sara, Rebeca e Lia</li><li><strong>Calebe:</strong> recebeu Hebrom como herança (<span class='versiculo'>Js 14:13-15</span>)</li><li><strong>Davi:</strong> reinou em Hebrom por sete anos e meio (<span class='versiculo'>2Sm 2:1-4</span>; <span class='versiculo'>5:5</span>)</li><li><strong>Absalão:</strong> iniciou sua rebelião em Hebrom (<span class='versiculo'>2Sm 15:7-10</span>)</li><li>Hoje, uma cidade palestina com o túmulo dos patriarcas</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 23; Gn 49:29-32; Js 14:13-15; 2Sm 2:1-4; 2Sm 5:5; 2Sm 15:7-10</span>"
},
{
    termo: "<span class='numero-ordem'>471.</span> <span class='nome-principal'>Peniel (Penuel)</span> <span class='subtitulo'>– lugar onde Jacó lutou com Deus</span>",
    definicao: "<p><strong>Peniel</strong> é o local junto ao rio Jaboque, onde Jacó lutou com um anjo (ou o próprio Deus) durante a noite, antes de encontrar Esaú (<span class='versiculo'>Gn 32:22-32</span>).</p><ul><li><strong>Novo nome:</strong> Jacó recebeu o nome de Israel</li><li><strong>Mancar:</strong> Jacó ficou manco da coxa</li><li><strong>Significado:</strong> Peniel ('face de Deus'), porque Jacó disse: <span class='destaque-amarelo'>'Vi a Deus face a face, e a minha vida foi salva'</span></li><li><strong>Gideão:</strong> derrubou a torre de Peniel (<span class='versiculo'>Jz 8:8-9,17</span>)</li><li>Peniel simboliza o encontro transformador com Deus e a perseverança na oração</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 32:22-32; Jz 8:8-9,17</span>"
},
{
    termo: "<span class='numero-ordem'>472.</span> <span class='nome-principal'>Berseba</span> <span class='subtitulo'>– cidade do juramento, onde Abraão e Isaque viveram</span>",
    definicao: "<p><strong>Berseba</strong> era uma cidade no sul de Judá, no limite do deserto.</p><ul><li><strong>Abraão:</strong> fez um juramento com Abimeleque sobre um poço (<span class='versiculo'>Gn 21:31-34</span>)</li><li><strong>Significado:</strong> 'poço do juramento'</li><li><strong>Isaque:</strong> cavou poços e fez aliança (<span class='versiculo'>Gn 26:23-33</span>)</li><li><strong>Limite:</strong> era o limite sul de Israel ('de Dã a Berseba')</li><li><strong>Adoração:</strong> mais tarde corrompida (<span class='versiculo'>Am 5:5</span>; <span class='versiculo'>8:14</span>)</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Gn 21:31-34; Gn 26:23-33; 1Sm 3:20; Am 5:5</span>"
},
{
    termo: "<span class='numero-ordem'>473.</span> <span class='nome-principal'>Dã</span> <span class='subtitulo'>– a cidade do norte, centro do culto ao bezerro de ouro</span>",
    definicao: "<p><strong>Dã</strong> era originalmente chamada Lais, foi conquistada pela tribo de Dã (<span class='versiculo'>Jz 18</span>).</p><ul><li><strong>Bezerro de ouro:</strong> Jeroboão I colocou um dos bezerros de ouro em Dã (<span class='versiculo'>1Rs 12:29-30</span>)</li><li><strong>Expressão:</strong> 'desde Dã até Berseba' designava todo o território de Israel</li><li>Dã representava a apostasia religiosa do reino do norte</li><li><strong>Arqueologia:</strong> escavações revelaram um altar e um templo do período israelita</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jz 18; 1Rs 12:29-30; Am 8:14</span>"
},
{
    termo: "<span class='numero-ordem'>474.</span> <span class='nome-principal'>Mispa (Mizpá)</span> <span class='subtitulo'>– local de assembleias e juízo em Israel</span>",
    definicao: "<p><strong>Mispa</strong> era uma cidade de Benjamim onde Samuel convocou todo o Israel para arrependimento, e ali os filisteus foram derrotados (<span class='versiculo'>1Sm 7:5-14</span>).</p><ul><li><strong>Saul:</strong> foi proclamado rei em Mispa (<span class='versiculo'>1Sm 10:17-24</span>)</li><li><strong>Gedalias:</strong> governador nomeado por Nabucodonosor, tinha sua sede em Mispa, onde foi assassinado (<span class='versiculo'>2Rs 25:22-26</span>; <span class='versiculo'>Jr 40-41</span>)</li><li><strong>Significado:</strong> 'torre de vigia' ou 'atalaia'</li><li>Representa o chamado à fidelidade e o local de decisões nacionais</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 7:5-14; 1Sm 10:17-24; 2Rs 25:22-26; Jr 40-41</span>"
},
{
    termo: "<span class='numero-ordem'>475.</span> <span class='nome-principal'>Vale de Elá</span> <span class='subtitulo'>– onde Davi derrotou Golias</span>",
    definicao: "<p>O <strong>Vale de Elá</strong> fica na Sefelá (terras baixas de Judá), entre Socó e Azeca (<span class='versiculo'>1Sm 17:1</span>). Foi o palco da batalha entre os filisteus e Israel, e onde Davi enfrentou Golias com sua funda.</p><ul><li><strong>Largura:</strong> cerca de 400 metros</li><li>Era uma rota estratégica</li><li><strong>Arqueologia:</strong> uma fortaleza foi encontrada no local (Khirbet Qeiyafa)</li><li>O vale simboliza a vitória da fé sobre a força humana e a confiança em Deus diante de gigantes</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Sm 17:1-58</span>"
},
{
    termo: "<span class='numero-ordem'>476.</span> <span class='nome-principal'>Deserto de Zim</span> <span class='subtitulo'>– onde Miriã morreu e Moisés feriu a rocha</span>",
    definicao: "<p>O <strong>Deserto de Zim</strong> é uma região desértica entre Cades e o Monte Hor. Foi ali que Miriã morreu e foi sepultada (<span class='versiculo'>Nm 20:1</span>).</p><ul><li><strong>Meribá:</strong> foi onde o povo reclamou por água, e Moisés feriu a rocha em vez de falar com ela (<span class='versiculo'>Nm 20:2-13</span>)</li><li>Por essa desobediência, Moisés foi impedido de entrar em Canaã</li><li>O deserto de Zim representa a tentação de desobedecer a Deus mesmo depois de tantos milagres</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Nm 20:1-13</span>"
},
{
    termo: "<span class='numero-ordem'>477.</span> <span class='nome-principal'>Monte Carmelo</span> <span class='subtitulo'>– local do confronto entre Elias e os profetas de Baal</span>",
    definicao: "<p>O <strong>Monte Carmelo</strong> é uma cadeia montanhosa no noroeste de Israel, junto ao mar Mediterrâneo.</p><ul><li><strong>Confronto:</strong> Elias desafiou os 450 profetas de Baal (<span class='versiculo'>1Rs 18:19-40</span>)</li><li>Deus respondeu com fogo do céu, consumindo o sacrifício</li><li><strong>Chuva:</strong> Elias orou pela chuva (<span class='versiculo'>1Rs 18:41-46</span>)</li><li>O Monte Carmelo é um símbolo da supremacia de Yahweh e da intercessão profética</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 18:19-46</span>"
},
{
    termo: "<span class='numero-ordem'>478.</span> <span class='nome-principal'>Vale de Josafá</span> <span class='subtitulo'>– lugar simbólico do juízo final</span>",
    definicao: "<p>O <strong>Vale de Josafá</strong> é mencionado apenas em <span class='versiculo'>Jl 3:2,12</span> como o vale onde Deus reunirá todas as nações para julgá-las.</p><ul><li><strong>Significado:</strong> 'Yahweh julga'</li><li><strong>Identificação:</strong> a tradição identifica o vale de Josafá com o vale do Cedrom</li><li><strong>Simbolismo:</strong> representa o dia do Senhor e a separação final entre justos e ímpios</li><li>Não deve ser confundido com o rei Josafá de Judá</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jl 3:2,12</span>"
},
{
    termo: "<span class='numero-ordem'>479.</span> <span class='nome-principal'>Monte Gerizim</span> <span class='subtitulo'>– monte da bênção, lugar de adoração dos samaritanos</span>",
    definicao: "<p>O <strong>Monte Gerizim</strong> é o monte onde Moisés ordenou que fosse proclamada a bênção sobre Israel (<span class='versiculo'>Dt 11:29</span>; <span class='versiculo'>27:12</span>).</p><ul><li><strong>Josué:</strong> cumpriu a ordem (<span class='versiculo'>Js 8:33-35</span>)</li><li><strong>Samaritanos:</strong> construíram seu templo no Gerizim</li><li><strong>Jesus:</strong> conversou com a mulher samaritana sobre a adoração no Gerizim versus Jerusalém (<span class='versiculo'>Jo 4:20-21</span>)</li><li>O monte simboliza a escolha da bênção pela obediência</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Dt 11:29; Dt 27:12; Js 8:33-35; Jo 4:20-21</span>"
},
{
    termo: "<span class='numero-ordem'>480.</span> <span class='nome-principal'>Monte Ebal</span> <span class='subtitulo'>– monte da maldição</span>",
    definicao: "<p>O <strong>Monte Ebal</strong> fica ao lado do Gerizim, onde Moisés ordenou a proclamação das maldições para os desobedientes (<span class='versiculo'>Dt 11:29</span>; <span class='versiculo'>27:13</span>).</p><ul><li><strong>Josué:</strong> construiu um altar de pedras não lavradas e gravou a Lei (<span class='versiculo'>Js 8:30-35</span>)</li><li>As bênçãos e maldições de Deuteronômio 28 foram lidas ali</li><li>Representa as consequências da desobediência e a seriedade da aliança</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Dt 11:29; Dt 27:13; Js 8:30-35</span>"
},
{
    termo: "<span class='numero-ordem'>481.</span> <span class='nome-principal'>O Monte da Tentação</span> <span class='subtitulo'>– onde Satanás tentou Jesus</span>",
    definicao: "<p>O <strong>Monte da Tentação</strong> é um monte elevado no deserto da Judeia, perto de Jericó, tradicionalmente identificado como o local onde Jesus jejuou por 40 dias e foi tentado por Satanás (<span class='versiculo'>Mt 4:1-11</span>; <span class='versiculo'>Lc 4:1-13</span>).</p><ul><li><strong>Tentação:</strong> o diabo mostrou-lhe todos os reinos do mundo e ofereceu-lhe poder</li><li><strong>Resposta:</strong> Jesus respondeu com as Escrituras</li><li>Simboliza o combate espiritual e a obediência perfeita de Cristo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 4:1-11; Lc 4:1-13</span>"
},
{
    termo: "<span class='numero-ordem'>482.</span> <span class='nome-principal'>O Gólgota (Calvário)</span> <span class='subtitulo'>– lugar da crucificação de Jesus</span>",
    definicao: "<p>O <strong>Gólgota</strong> é o lugar fora das muralhas de Jerusalém, cujo nome significa 'lugar da caveira' (aramaico Gulgolta). Ali Jesus foi crucificado entre dois ladrões (<span class='versiculo'>Mt 27:33</span>; <span class='versiculo'>Mc 15:22</span>; <span class='versiculo'>Lc 23:33</span>; <span class='versiculo'>Jo 19:17</span>).</p><ul><li><strong>Identificação:</strong> a tradição católica identifica o local como a Basílica do Santo Sepulcro</li><li>O Gólgota representa o centro da redenção: o sacrifício de Cristo pelos pecados da humanidade</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 27:33; Mc 15:22; Lc 23:33; Jo 19:17</span>"
},
{
    termo: "<span class='numero-ordem'>483.</span> <span class='nome-principal'>Getsêmani</span> <span class='subtitulo'>– jardim onde Jesus orou antes da crucificação</span>",
    definicao: "<p><strong>Getsêmani</strong> é um jardim ou olival no sopé do Monte das Oliveiras, onde Jesus costumava reunir-se com os discípulos (<span class='versiculo'>Mt 26:36</span>; <span class='versiculo'>Mc 14:32</span>; <span class='versiculo'>Jo 18:1</span>).</p><ul><li><strong>Agonia:</strong> Jesus agonizou em oração, suou gotas de sangue</li><li><strong>Traição:</strong> foi traído por Judas e preso</li><li><strong>Significado:</strong> 'prensa de azeite'</li><li>Simboliza a luta solitária de Cristo contra o pecado e a rendição à vontade do Pai: <span class='destaque-amarelo'>'Não seja como eu quero, mas como tu queres'</span></li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 26:36-46; Mc 14:32-42; Lc 22:39-46; Jo 18:1-2</span>"
},
{
    termo: "<span class='numero-ordem'>484.</span> <span class='nome-principal'>Cades-Barneia</span> <span class='subtitulo'>– lugar da incredulidade de Israel</span>",
    definicao: "<p><strong>Cades-Barneia</strong> foi um oásis no deserto de Parã, onde os doze espias foram enviados a Canaã (<span class='versiculo'>Nm 13:26</span>).</p><ul><li><strong>Rebelião:</strong> a maioria deu relatório negativo, e o povo se rebelou, resultando em 40 anos de peregrinação no deserto (<span class='versiculo'>Nm 14</span>)</li><li><strong>Miriã:</strong> morreu ali (<span class='versiculo'>Nm 20:1</span>)</li><li><strong>Meribá:</strong> Moisés feriu a rocha em Meribá de Cades (<span class='versiculo'>Nm 20:10-13</span>)</li><li>Cades representa a decisão de confiar em Deus ou duvidar</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Nm 13:26; Nm 14; Nm 20:1-13</span>"
},
{
    termo: "<span class='numero-ordem'>485.</span> <span class='nome-principal'>Vale do Cedrom</span> <span class='subtitulo'>– local de juízo e de passagem de Davi na fuga de Absalão</span>",
    definicao: "<p>O <strong>Vale do Cedrom</strong> é um vale entre Jerusalém e o Monte das Oliveiras.</p><ul><li><strong>Davi:</strong> atravessou o Cedrom descalço e chorando quando fugia de Absalão (<span class='versiculo'>2Sm 15:23</span>)</li><li><strong>Josias:</strong> removeu ídolos e os queimou no Cedrom (<span class='versiculo'>2Rs 23:4,6,12</span>)</li><li><strong>Jesus:</strong> atravessou o Cedrom para ir ao Getsêmani (<span class='versiculo'>Jo 18:1</span>)</li><li>Simboliza o lamento, o arrependimento e a transição para o sofrimento</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Sm 15:23; 2Rs 23:4,6,12; Jr 31:40; Jo 18:1</span>"
},
{
    termo: "<span class='numero-ordem'>486.</span> <span class='nome-principal'>A estrada de Damasco</span> <span class='subtitulo'>– onde Saulo (Paulo) foi convertido</span>",
    definicao: "<p>A <strong>estrada de Damasco</strong> liga Jerusalém a Damasco (c. 250 km). Foi ali que Saulo de Tarso, a caminho para prender cristãos, foi surpreendido por uma luz do céu e ouviu a voz de Jesus: <span class='destaque-amarelo'>'Saulo, Saulo, por que me persegues?'</span> (<span class='versiculo'>At 9:1-9</span>; <span class='versiculo'>22:6-11</span>; <span class='versiculo'>26:12-18</span>).</p><ul><li><strong>Cegueira:</strong> ficou cego três dias</li><li><strong>Batismo:</strong> Ananias o batizou em Damasco</li><li>Simboliza a conversão radical e o chamado de Deus para um perseguidor se tornar apóstolo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>At 9:1-9; At 22:6-11; At 26:12-18</span>"
},
{
    termo: "<span class='numero-ordem'>487.</span> <span class='nome-principal'>O fundador de um reino – personagem anônimo: o homem de Deus que profetizou contra o altar de Betel (1Rs 13)</span> <span class='subtitulo'>– profeta anônimo que desobedeceu a ordem divina</span>",
    definicao: "<p>O <strong>homem de Deus</strong> (anônimo) foi enviado de Judá a Betel para profetizar contra o altar de Jeroboão I. Ele predisse que um rei chamado Josias profanaria o altar (<span class='versiculo'>1Rs 13:1-3</span>).</p><ul><li><strong>Milagre:</strong> Jeroboão tentou prendê-lo, mas sua mão ficou seca; o profeta o curou</li><li><strong>Desobediência:</strong> no caminho de volta, um velho profeta de Betel o enganou, dizendo que um anjo lhe ordenara trazê-lo à sua casa</li><li><strong>Morte:</strong> o homem de Deus desobedeceu e foi morto por um leão</li><li>Representa a seriedade da obediência à palavra de Deus e o perigo de dar ouvidos a revelações falsas</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>1Rs 13:1-32</span>"
},
{
    termo: "<span class='numero-ordem'>488.</span> <span class='nome-principal'>O anjo da igreja de Éfeso (Ap 2:1)</span> <span class='subtitulo'>– personagem simbólico</span>",
    definicao: "<p>O <strong>anjo da igreja de Éfeso</strong> é mencionado em <span class='versiculo'>Ap 2:1-7</span>. É provavelmente o líder espiritual (bispo) ou uma personificação da igreja.</p><ul><li><strong>Elogio:</strong> elogiado por suas obras</li><li><strong>Repreensão:</strong> repreendido por ter abandonado o primeiro amor</li><li><strong>Promessa:</strong> comer da árvore da vida</li><li>Simboliza a responsabilidade dos líderes e a necessidade de arrependimento</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 2:1-7</span>"
},
{
    termo: "<span class='numero-ordem'>489.</span> <span class='nome-principal'>O anjo da igreja de Esmirna (Ap 2:8-11)</span> <span class='subtitulo'>– elogiado por sua perseverança na perseguição</span>",
    definicao: "<p>O <strong>anjo da igreja de Esmirna</strong> é elogiado por ser rico apesar de pobre, e por suportar calúnias. Deus promete a coroa da vida.</p><ul><li>Esmirna é a única igreja sem repreensão</li><li>O anjo representa os cristãos perseguidos que permanecem fiéis até a morte</li><li>Recebem o galardão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 2:8-11</span>"
},
{
    termo: "<span class='numero-ordem'>490.</span> <span class='nome-principal'>O anjo da igreja de Pérgamo (Ap 2:12-17)</span> <span class='subtitulo'>– advertido por tolerar a doutrina de Balaão e dos nicolaítas</span>",
    definicao: "<p>O <strong>anjo da igreja de Pérgamo</strong> é elogiado por manter a fé mesmo com o martírio de Antipas, mas repreendido por tolerar falsos mestres.</p><ul><li><strong>Promessa:</strong> o maná escondido e a pedra branca com um novo nome</li><li>O anjo simboliza a luta contra o sincretismo religioso</li><li>Necessidade de separação do mundo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 2:12-17</span>"
},
{
    termo: "<span class='numero-ordem'>491.</span> <span class='nome-principal'>O anjo da igreja de Tiatira (Ap 2:18-29)</span> <span class='subtitulo'>– tolerava a falsa profetisa Jezabel</span>",
    definicao: "<p>O <strong>anjo da igreja de Tiatira</strong> tem obras, amor, fé e perseverança, mas tolera a mulher Jezabel que ensina imoralidade. Será julgado.</p><ul><li><strong>Promessa:</strong> autoridade sobre as nações e a estrela da manhã</li><li>Simboliza o perigo de tolerar o pecado em nome da graça</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 2:18-29</span>"
},
{
    termo: "<span class='numero-ordem'>492.</span> <span class='nome-principal'>O anjo da igreja de Sardes (Ap 3:1-6)</span> <span class='subtitulo'>– tem nome de vivo, mas está morto</span>",
    definicao: "<p>O <strong>anjo da igreja de Sardes</strong> aparenta estar viva, mas espiritualmente está morta. São exortados a vigiar e fortalecer o que resta.</p><ul><li><strong>Promessa:</strong> os poucos que não contaminaram as vestes andarão de branco</li><li>O anjo representa a hipocrisia religiosa e a necessidade de arrependimento genuíno</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 3:1-6</span>"
},
{
    termo: "<span class='numero-ordem'>493.</span> <span class='nome-principal'>O anjo da igreja de Filadélfia (Ap 3:7-13)</span> <span class='subtitulo'>– igreja fiel, com pouca força, que guardou a palavra</span>",
    definicao: "<p>O <strong>anjo da igreja de Filadélfia</strong> é elogiado por sua fidelidade, mesmo com pouca força. Deus abre uma porta que ninguém pode fechar.</p><ul><li><strong>Promessa:</strong> livrar da hora da provação e fazer do vencedor uma coluna no templo</li><li>Filadélfia representa os remanescentes fiéis que perseveram</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 3:7-13</span>"
},
{
    termo: "<span class='numero-ordem'>494.</span> <span class='nome-principal'>O anjo da igreja de Laodiceia (Ap 3:14-22)</span> <span class='subtitulo'>– igreja morna, que será vomitada</span>",
    definicao: "<p>O <strong>anjo da igreja de Laodiceia</strong> se considera rico, mas é miserável, cega e nua. É chamada ao arrependimento.</p><ul><li><strong>Promessa:</strong> o vencedor se assentará no trono</li><li><span class='destaque-amarelo'>'Eis que estou à porta e bato'</span></li><li>Laodiceia simboliza o cristianismo nominal, autossuficiente e sem fervor</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Ap 3:14-22</span>"
},
{
    termo: "<span class='numero-ordem'>495.</span> <span class='nome-principal'>Semaías, o neelamita (Jr 29:24-32)</span> <span class='subtitulo'>– falso profeta que se opôs a Jeremias</span>",
    definicao: "<p><strong>Semaías</strong>, natural de Neelã, era um falso profeta na Babilônia durante o exílio.</p><ul><li><strong>Ação:</strong> enviou cartas a Jerusalém e ao sacerdote Sofonias, proclamando que Deus havia levantado profetas na Babilônia e condenando Jeremias</li><li><strong>Profecia:</strong> Jeremias profetizou que Semaías não teria descendente que visse o bem (<span class='versiculo'>Jr 29:31-32</span>)</li><li>Ele representa os falsos profetas que contradizem a palavra de Deus e semeiam confusão</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jr 29:24-32</span>"
},
{
    termo: "<span class='numero-ordem'>496.</span> <span class='nome-principal'>Acabe, filho de Colaías</span> <span class='subtitulo'>– falso profeta na Babilônia, que seria assado ao fogo</span>",
    definicao: "<p><strong>Acabe</strong>, filho de Colaías, foi um falso profeta na Babilônia, mencionado em <span class='versiculo'>Jr 29:21-23</span>.</p><ul><li><strong>Crime:</strong> profetizou mentiras em nome de Deus e cometeu adultério</li><li><strong>Punição:</strong> Nabucodonosor o assou ao fogo</li><li>Acabe (outro) é exemplo do juízo severo contra os que profanam o nome de Deus</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jr 29:21-23</span>"
},
{
    termo: "<span class='numero-ordem'>497.</span> <span class='nome-principal'>Zedequias, filho de Maaseias</span> <span class='subtitulo'>– falso profeta na Babilônia, também assado ao fogo</span>",
    definicao: "<p><strong>Zedequias</strong>, filho de Maaseias, foi companheiro de Acabe, filho de Colaías.</p><ul><li><strong>Crime:</strong> profetizou mentiras e cometeu adultério</li><li>Foi morto por Nabucodonosor, e seu nome tornou-se maldição entre os exilados</li><li>Representa a ruína dos líderes religiosos corruptos</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jr 29:21-23</span>"
},
{
    termo: "<span class='numero-ordem'>498.</span> <span class='nome-principal'>O servo de Eliseu que viu o exército celestial (2Rs 6:15-17)</span> <span class='subtitulo'>– anônimo</span>",
    definicao: "<p>O <strong>servo de Eliseu</strong> acordou cedo e viu o exército sírio cercando a cidade de Dotã. Desesperou-se, mas Eliseu orou: <span class='destaque-amarelo'>'Senhor, abre-lhe os olhos para que veja'</span>.</p><ul><li>Deus abriu os olhos do servo, e ele viu o monte cheio de cavalos e carros de fogo ao redor de Eliseu (<span class='versiculo'>2Rs 6:15-17</span>)</li><li>Este servo representa a necessidade de visão espiritual para enxergar a proteção divina em meio aos perigos</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>2Rs 6:15-17</span>"
},
{
    termo: "<span class='numero-ordem'>499.</span> <span class='nome-principal'>O soldado que perfurou o lado de Jesus (Jo 19:34)</span> <span class='subtitulo'>– anônimo</span>",
    definicao: "<p>O <strong>soldado que perfurou o lado de Jesus</strong> era um soldado romano que, para certificar a morte de Jesus, perfurou seu lado com uma lança, e imediatamente saiu sangue e água (<span class='versiculo'>Jo 19:34</span>).</p><ul><li><strong>Cumprimento:</strong> o ato cumpriu a profecia de que nenhum osso seria quebrado (<span class='versiculo'>Êx 12:46</span>; <span class='versiculo'>Sl 34:20</span>)</li><li><strong>Zacarias:</strong> 'olhariam para aquele que traspassaram' (<span class='versiculo'>Zc 12:10</span>)</li><li><strong>Tradição:</strong> chama esse soldado de Longino (nome não bíblico)</li><li>Representa a testemunha involuntária da divindade de Cristo</li><li>O sangue e a água simbolizam a expiação e o batismo</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Jo 19:34-37; Zc 12:10</span>"
},
{
    termo: "<span class='numero-ordem'>500.</span> <span class='nome-principal'>O centurião da crucificação</span> <span class='subtitulo'>– que declarou: 'Verdadeiramente este homem era Filho de Deus'</span>",
    definicao: "<p>O <strong>centurião da crucificação</strong> era um centurião romano encarregado da crucificação. Ao ver o terremoto, as trevas e a forma como Jesus expirou, exclamou: <span class='destaque-amarelo'>'Verdadeiramente este homem era Filho de Deus'</span> (<span class='versiculo'>Mc 15:39</span>) ou 'Justo' (<span class='versiculo'>Lc 23:47</span>).</p><ul><li>Este centurião é o primeiro gentio, após a morte de Cristo, a confessar sua divindade</li><li>Seu nome não é dado; a tradição o chama de Longino (confundido com o soldado da lança)</li><li>Representa o reconhecimento pagão da majestade de Jesus</li><li>Simboliza a abertura do evangelho aos gentios</li><li>Com este personagem, encerramos a lista de 500 personagens bíblicos</li></ul>",
    referencias: "<span class='label-ref'>📖 Referências:</span> <span class='refs'>Mt 27:54; Mc 15:39; Lc 23:47</span>"
}
]
};
